import { useCallback, useMemo } from 'react';
import { workflowDefinitionApi } from '../services/workflowDefinitionApi';
import { showToast } from '../../../shared/ToastManager';
import { getWarningMessage } from '../../../shared/utils/formChangeDetection';
import { CANCEL_MESSAGES, CANCEL_ERROR_MESSAGES } from '../../constants/cancelMessages';
import { logger } from '../../../shared/utils/logger';

// Toast notification duration (30 seconds)
const TOAST_DURATION = 30000;

/**
 * Custom hook for managing WorkflowDefinitionManager event handlers
 * Extracts all handler logic to make the component more modular
 * PERFORMANCE: Uses useMemo and useCallback for optimization
 */
export const useWorkflowDefinitionHandlers = ({
  workflowId: currentWorkflowId,
  taskId,
  onSuccess,
  onCancel,
  formRef,
  taskDetailRef,
  saving,
  setSaving,
  setValidating,
  setDrawerOpen,
  setError,
  setCurrentTask,
  setTaskDetailLoading,
  setTaskDetail,
  setTaskFetchError,
  setFormChanged,
  setSearchUDFModalOpen,
  setAdhocSettingsModalOpen,
  setPreconditionsModalOpen,
  setInsertSnippetModalOpen,
  setConfirmationDialog,
  currentTask,
  taskDetail,
  formChanged,
  setWorkflowId,
  setInitialData,
  setWorkflowTreeData,
  setLoading,
  setFullPageLoader,
  fetchTreeData,
  setTreeDataError
}) => {

  const handleSaveClick = useCallback(async () => {
    if (!formRef.current) {
      showToast.error('Form not available', TOAST_DURATION);
      return;
    }

    const formData = formRef.current.getFormData ? formRef.current.getFormData() : null;
    if (!formData) {
      showToast.error('Form data not available', TOAST_DURATION);
      return;
    }

    try {
      setValidating(true);
      const isFormValid = await formRef.current.isFormValid();
      if (!isFormValid) {
        showToast.error('Please fix validation errors before saving', TOAST_DURATION);
        if (formRef.current && formRef.current.focusFirstError) {
          formRef.current.focusFirstError();
        }
        return;
      }
    } catch (validationError) {
      showToast.error(validationError.message || 'Form validation failed', TOAST_DURATION);
      return;
    } finally {
      setValidating(false);
    }

    setSaving(true);
    setError(null);
    setFullPageLoader({
      open: true,
      message: 'Saving workflow definition...'
    });

    try {
      const result = await workflowDefinitionApi.saveWorkflowDefinition(formData);
      
      if (result.success) {
        showToast.success(result.message || 'Workflow definition saved successfully!', TOAST_DURATION);
        
        setDrawerOpen(false);
        
        if (!currentWorkflowId && result.workflowDefId) {
          const currentUrl = new URL(window.location.href);
          currentUrl.searchParams.set('id', result.workflowDefId);
          window.location.href = currentUrl.toString();
          return;
        }
        
        // Update initialData with the saved formData (no need to fetch again)
        if (currentWorkflowId && formData) {
          setInitialData({
            ...formData,
            Id: currentWorkflowId
          });
        }
        
        if (onSuccess) {
          onSuccess(result);
        }
      } else {
        showToast.error(result.message || 'Failed to save workflow definition', TOAST_DURATION);
      }
    } catch (error) {
      const errorMessage = error.message || 'Failed to save workflow definition';
      showToast.error(errorMessage, TOAST_DURATION);
    } finally {
      setSaving(false);
      setFullPageLoader(prev => ({ ...prev, open: false }));
    }
  }, [formRef, setSaving, setValidating, setDrawerOpen, setError, onSuccess, currentWorkflowId, setWorkflowId, setInitialData, setWorkflowTreeData, setLoading, setFullPageLoader]);

  const handleCancel = useCallback(() => {
    if (currentWorkflowId && currentWorkflowId > 0) {
      setDrawerOpen(false);
      setError(null);
    } else {
      if (onCancel) {
        onCancel();
      } else {
        window.location.href = '/WorkflowDef';
      }
    }
  }, [currentWorkflowId, setDrawerOpen, setError, onCancel]);

  const handleCloseDrawer = useCallback(() => {
    if (currentWorkflowId && currentWorkflowId > 0) {
      setDrawerOpen(false);
      setError(null);
    } else {
      handleCancel();
    }
  }, [currentWorkflowId, setDrawerOpen, setError, handleCancel]);

  const showConfirmationDialog = useCallback((title, message, onConfirm, options = {}) => {
    setConfirmationDialog({
      open: true,
      title,
      message,
      onConfirm: () => {
        setConfirmationDialog(prev => ({ ...prev, open: false }));
        onConfirm();
      },
      onCancel: () => {
        setConfirmationDialog(prev => ({ ...prev, open: false }));
      },
      confirmText: options.confirmText || 'Yes',
      cancelText: options.cancelText || 'No',
      severity: options.severity || 'warning'
    });
  }, [setConfirmationDialog]);

  /**
   * Handles task cancellation with change detection and confirmation
   * @param {Object} currentTaskToCancel - The task to cancel
   * @param {number|string} currentTaskToCancel.id - Task ID
   * @param {boolean} [currentTaskToCancel.NewlyCreated] - Whether task is newly created
   * @param {boolean} [currentTaskToCancel.IsNewlyCreated] - Alternative newly created flag (backend inconsistency)
   * @returns {Promise<void>}
   */
  const handleTaskCancel = useCallback(async (currentTaskToCancel) => {
    logger.debug('handleTaskCancel invoked', { 
      taskId: currentTaskToCancel?.id,
      workflowId: currentWorkflowId,
      hasTaskDetailRef: !!taskDetailRef?.current
    });
    
    try {
      // Validate inputs
      if (!currentWorkflowId || !currentTaskToCancel?.id) {
        logger.error('Invalid parameters for cancelTask', {
          currentWorkflowId,
          taskId: currentTaskToCancel?.id
        });
        
        // Close drawer to unblock user
        setTaskDetail(null);
        setCurrentTask(null);
        setFormChanged(false);
        return;
      }
      
      // Check if task is newly created (handle backend property inconsistency)
      const isNewlyCreated = currentTaskToCancel?.NewlyCreated === true || currentTaskToCancel?.IsNewlyCreated === true;
      
      // Check for unsaved changes using the child component's checkForChanges method
      let hasChanges = false;
      if (taskDetailRef?.current?.checkForChanges) {
        hasChanges = taskDetailRef.current.checkForChanges();
        logger.debug('Change detection result', { hasChanges, isNewlyCreated });
      } else {
        logger.warn('checkForChanges method not available on taskDetailRef');
      }
      
      // Show confirmation if task is newly created OR has unsaved changes
      if (isNewlyCreated || hasChanges) {
        const messages = isNewlyCreated 
          ? CANCEL_MESSAGES.NEWLY_CREATED 
          : CANCEL_MESSAGES.HAS_CHANGES;
        
        logger.debug('Showing confirmation dialog', { type: isNewlyCreated ? 'newly_created' : 'has_changes' });
        
        showConfirmationDialog(
          messages.title,
          messages.message,
          async () => {
            logger.debug('User confirmed cancel action');
            
            try {
              if (isNewlyCreated) {
                // Delete newly created task that was never saved
                const result = await workflowDefinitionApi.cancelTask(currentWorkflowId, currentTaskToCancel.id, false, true);
                logger.info('Newly created task deleted, reloading page', result);
                window.location.reload();
              } else {
                // Revert changes for existing task
                const result = await workflowDefinitionApi.cancelTask(currentWorkflowId, currentTaskToCancel.id, false, false);
                logger.info('Task changes reverted successfully', result);
                
                // Close the task detail drawer
                setTaskDetail(null);
                setCurrentTask(null);
                setFormChanged(false);
              }
            } catch (apiError) {
              logger.error('API call failed during cancel', apiError);
              
              // Close drawer anyway to unblock user
              setTaskDetail(null);
              setCurrentTask(null);
              setFormChanged(false);
            }
          },
          {
            confirmText: messages.confirmText,
            cancelText: messages.cancelText
          }
        );
      } else {
        logger.debug('No changes detected, closing drawer immediately');
        // No changes, just close the task detail drawer
        setTaskDetail(null);
        setCurrentTask(null);
        setFormChanged(false);
      }
    } catch (error) {
      logger.error('Unexpected error in handleTaskCancel', error);
      
      // Always close drawer to prevent user from being stuck
      setTaskDetail(null);
      setCurrentTask(null);
      setFormChanged(false);
    }
  }, [currentWorkflowId, setTaskDetail, setCurrentTask, setFormChanged, taskDetailRef, showConfirmationDialog]);

  const handleToastClose = useCallback(() => {
  }, []);

  const handleTabChange = useCallback((event, newValue) => {
  }, []);

  const handleNodeSelect = useCallback(async (node, options = {}) => {
    if (!node || !node.id) {
      setCurrentTask(null);
      setTaskDetail(null);
      return;
    }

    const { skipConfirmation = false } = options;

    // If skipConfirmation is true, directly select the node without checking for unsaved changes
    if (skipConfirmation) {
      selectNode(node);
      return;
    }

    const isNew = taskDetailRef?.current?.isNewlyCreated;
    
    let hasChanges = false;
    if (taskDetailRef?.current?.checkForChanges) {
      hasChanges = taskDetailRef.current.checkForChanges();
    } else {
      hasChanges = formChanged;
    }

    if ((isNew || hasChanges) && currentTask) {
      const warningMessage = getWarningMessage(isNew, hasChanges);
      
      showConfirmationDialog(
        warningMessage?.title || 'Unsaved Changes',
        warningMessage?.message || 'Changes were made, do you want to continue without saving?',
        () => {
          selectNode(node);
        },
        {
          confirmText: 'Continue',
          cancelText: 'Cancel',
          severity: warningMessage?.severity || 'warning'
        }
      );
      return;
    }

    if (currentTask && taskDetail && taskDetail.NewlyCreated) {
      showConfirmationDialog(
        'New Task Not Saved',
        'The new task definition has not yet been saved. Any changes will be lost and the element removed by canceling. Do you want to continue without saving?',
        () => {
          selectNode(node);
        },
        {
          confirmText: 'Continue',
          cancelText: 'Cancel',
          severity: 'error'
        }
      );
      return;
    }

    selectNode(node);
  }, [currentWorkflowId, formChanged, currentTask, taskDetail, showConfirmationDialog, taskDetailRef, selectNode]);

  const selectNode = useCallback(async (node) => {
    setCurrentTask(node);
    setTaskDetailLoading(true);
    setTaskDetail(null);
    setTaskFetchError(null);

    try {
      const taskDetailData = await workflowDefinitionApi.getTaskDetail(currentWorkflowId, node.id);
      
      if (!taskDetailData?.success) {
        setTaskDetail(null);
        setTaskDetailLoading(false);
        setTaskFetchError(taskDetailData?.message || 'Failed to load task details');
        showToast.error(taskDetailData?.message || 'Failed to load task details', TOAST_DURATION);
        return;
      }
      
      const receivedId = taskDetailData?.data?.Id || taskDetailData?.data?.id;
      const expectedId = node.id;
      const idMatches = String(receivedId) === String(expectedId);
      
      if (taskDetailData?.data && idMatches) {
        setTaskDetail(taskDetailData.data);
        setTaskFetchError(null);
      } else {
        setTaskDetail(null);
      }
    } catch (err) {
      showToast.error('Failed to load task details', TOAST_DURATION);
      setTaskDetail(null);
    } finally {
      setTaskDetailLoading(false);
    }
  }, [currentWorkflowId, setCurrentTask, setTaskDetailLoading, setTaskDetail, setTaskFetchError, setError]);

  const handleTreeAction = useCallback((actionObj) => {
    switch (actionObj.actionType) {
      case 'TakeOwnership':
        break;
      case 'ReleaseOwnership':
        break;
      case 'MarkComplete':
        break;
      default:
        break;
    }
  }, []);

  const handleTreeError = useCallback((error) => {
    const errorMessage = typeof error === 'string' ? error : (error.message || 'Tree operation failed');
    setError(errorMessage);
  }, [setError]);

  const handleSearchUDFOpen = useCallback(() => {
    setSearchUDFModalOpen(true);
  }, [setSearchUDFModalOpen]);

  const handleSearchUDFClose = useCallback(() => {
    setSearchUDFModalOpen(false);
  }, [setSearchUDFModalOpen]);

  const handleAdhocSettingsOpen = useCallback(() => {
    setAdhocSettingsModalOpen(true);
  }, [setAdhocSettingsModalOpen]);

  const handleAdhocSettingsClose = useCallback(() => {
    setAdhocSettingsModalOpen(false);
  }, [setAdhocSettingsModalOpen]);

  const handleAdhocSettingsSave = useCallback(async (settingsData) => {
    try {
      setInitialData(prevData => {
        if (prevData) {
          return {
            ...prevData,
            ExpectedDuration: settingsData.expectedDuration || prevData.ExpectedDuration || 0,
            AllowAdHoc: settingsData.allowAdHoc !== undefined ? settingsData.allowAdHoc : (prevData.AllowAdHoc !== false)
          };
        }
        return prevData;
      });
      
      setAdhocSettingsModalOpen(false);
    } catch (error) {
      showToast.error('Failed to update ad-hoc settings', TOAST_DURATION);
    }
  }, [setAdhocSettingsModalOpen, setInitialData]);

  const handlePreconditionsOpen = useCallback(() => {
    setPreconditionsModalOpen(true);
  }, [setPreconditionsModalOpen]);

  const handlePreconditionsClose = useCallback(() => {
    setPreconditionsModalOpen(false);
  }, [setPreconditionsModalOpen]);

  const handleInsertSnippetOpen = useCallback(() => {
    setInsertSnippetModalOpen(true);
  }, [setInsertSnippetModalOpen]);

  const handleInsertSnippetClose = useCallback(() => {
    setInsertSnippetModalOpen(false);
  }, [setInsertSnippetModalOpen]);

  const handleTreeDataRefresh = useCallback(async () => {
    if (!currentWorkflowId || currentWorkflowId === 0) {
      return [];
    }
    
    return await fetchTreeData();
  }, [currentWorkflowId, fetchTreeData]);

  const handleTaskSettingsSave = useCallback(async (taskSettingsData) => {
    try {
      const { workflowDefinitionApi } = await import('../services/workflowDefinitionApi');
      const result = await workflowDefinitionApi.saveTaskDetail(taskSettingsData, true);
      
      if (result.success) {
        if (taskSettingsData?.Id && currentWorkflowId) {
          try {
            const updatedTaskDetail = await workflowDefinitionApi.getTaskDetail(currentWorkflowId, taskSettingsData.Id);
            if (updatedTaskDetail?.success && updatedTaskDetail?.data) {
              if (setTaskDetail) {
                setTaskDetail(updatedTaskDetail.data);
              }
            }
          } catch (refreshError) {
          }
        }
      }
      
      return result;
    } catch (error) {
      showToast.error('Failed to save task settings', TOAST_DURATION);
      throw error;
    }
  }, [currentWorkflowId, setTaskDetail]);

  // PERFORMANCE: Memoize handlers object to prevent unnecessary re-renders
  const handlers = useMemo(() => ({
    handleSaveClick,
    handleTaskSettingsSave,
    handleCancel,
    handleCloseDrawer,
    handleTaskCancel,
    handleToastClose,
    handleTabChange,
    handleNodeSelect,
    handleTreeAction,
    handleTreeError,
    handleSearchUDFOpen,
    handleSearchUDFClose,
    handleAdhocSettingsOpen,
    handleAdhocSettingsClose,
    handleAdhocSettingsSave,
    handlePreconditionsOpen,
    handlePreconditionsClose,
    handleInsertSnippetOpen,
    handleInsertSnippetClose,
    handleTreeDataRefresh,
    showConfirmationDialog
  }), [
    handleSaveClick,
    handleTaskSettingsSave,
    handleCancel,
    handleCloseDrawer,
    handleToastClose,
    handleTabChange,
    handleNodeSelect,
    handleTreeAction,
    handleTreeError,
    handleSearchUDFOpen,
    handleSearchUDFClose,
    handleAdhocSettingsOpen,
    handleAdhocSettingsClose,
    handleAdhocSettingsSave,
    handlePreconditionsOpen,
    handlePreconditionsClose,
    handleInsertSnippetOpen,
    handleInsertSnippetClose,
    handleTreeDataRefresh,
    showConfirmationDialog
  ]);

  return handlers;
};
