import { useState, useEffect, useCallback, useRef, useMemo } from 'react';
import { workflowDefinitionApi } from '../services/workflowDefinitionApi';
import { showToast } from '../../../shared/ToastManager';
import { hasFormChangesByOmit } from '../../../shared/utils/formChangeDetection';

/**
 * Custom hook for managing WorkflowDefinitionManager state
 * Extracts all state management logic to make the component more modular
 */
export const useWorkflowDefinitionState = ({ workflowId, subcategoryOptionsByCategoryJson, onSuccess, onCancel }) => {
  // Core state - Initialize drawer based on whether this is a new workflow
  const [drawerOpen, setDrawerOpen] = useState(!workflowId || workflowId === 0);
  const [saving, setSaving] = useState(false);
  const [validating, setValidating] = useState(false);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [activeTab, setActiveTab] = useState(0);
  
  // Form and data state
  const formRef = useRef(null);
  const [options, setOptions] = useState({
    workflowTypes: [],
    stateTransitionDomains: [],
    categories: [],
    subcategories: [],
    initializerTypes: []
  });
  const [initialData, setInitialData] = useState(null);
  
  // Tree and task state
  const [workflowTreeData, setWorkflowTreeData] = useState(null);
  const [treeDataError, setTreeDataError] = useState(null);
  const [currentTask, setCurrentTask] = useState(null);
  const [taskDetailLoading, setTaskDetailLoading] = useState(false);
  const [taskDetail, setTaskDetail] = useState(null);
  const [taskFetchError, setTaskFetchError] = useState(null);
  const [formChanged, setFormChanged] = useState(false);
  
  // Modal states
  const [searchUDFModalOpen, setSearchUDFModalOpen] = useState(false);
  const [adhocSettingsModalOpen, setAdhocSettingsModalOpen] = useState(false);
  const [preconditionsModalOpen, setPreconditionsModalOpen] = useState(false);
  const [insertSnippetModalOpen, setInsertSnippetModalOpen] = useState(false);
  const [settingsModalOpen, setSettingsModalOpen] = useState(false);
  
  // Full page loader state
  const [fullPageLoader, setFullPageLoader] = useState({
    open: false,
    message: 'Loading...'
  });
  
  // Confirmation dialog state
  const [confirmationDialog, setConfirmationDialog] = useState({
    open: false,
    title: '',
    message: '',
    onConfirm: null,
    onCancel: null,
    confirmText: 'Yes',
    cancelText: 'No',
    severity: 'warning'
  });
  

  // Additional state for dynamic workflowId management
  const [currentWorkflowId, setCurrentWorkflowId] = useState(workflowId);

  // Auto-open drawer when component mounts (only for new workflows)
  useEffect(() => {
    // Only auto-open drawer for new workflows (workflowId is 0 or null)
    const isNewWorkflow = !workflowId || workflowId === 0;
    setDrawerOpen(isNewWorkflow);
  }, [workflowId]);

  // Update currentWorkflowId when workflowId prop changes
  useEffect(() => {
    setCurrentWorkflowId(workflowId);
  }, [workflowId]);

  // Load data function
  const loadData = useCallback(async () => {
    setLoading(true);
    setError(null);
    
    try {
      // PERFORMANCE: Parallelize independent API calls
      const loadPromises = [];
      
      // Load options (always needed)
      loadPromises.push(workflowDefinitionApi.getOptions());
      
      // Load workflow data if editing
      if (workflowId) {
        loadPromises.push(workflowDefinitionApi.getWorkflowDefinition(workflowId));
      }
      
      // Execute API calls in parallel
      const results = await Promise.all(loadPromises);
      const optionsData = results[0];
      const workflowData = workflowId ? results[1] : null;
      
      setOptions(optionsData);

      if (workflowData) {
        // Use server-side subcategory options if available
        if (subcategoryOptionsByCategoryJson && Object.keys(subcategoryOptionsByCategoryJson).length > 0) {
          workflowData.subcategoryOptionsByCategoryJson = subcategoryOptionsByCategoryJson;
        }
        
        setInitialData(workflowData);
        
        // PERFORMANCE: Extract tree data directly from workflow definition
        // Avoids making a duplicate API call to getWorkflowTree
        if (workflowData.Tree) {
          const transformNode = (node) => {
            return {
              ...node,
              title: node.Name,
              children: node.Children ? node.Children.map(transformNode) : [],
              expanded: true,
              id: node.Attributes ? node.Attributes['data-item-id'] : null,
              sectionMenu: node.SectionMenu || []
            };
          };
          
          const transformedTree = Array.isArray(workflowData.Tree) 
            ? workflowData.Tree.map(transformNode)
            : [transformNode(workflowData.Tree)];
          
          setWorkflowTreeData(transformedTree);
          setTreeDataError(null);
        }
        
        // If category is already selected, fetch subcategories for it (non-blocking)
        if (workflowData.CategoryCode) {
          try {
            const subcategories = await workflowDefinitionApi.getSubcategories(workflowData.CategoryCode);
            if (subcategories && subcategories.length > 0) {
              // Update the subcategory options in the loaded data
              const updatedData = { ...workflowData };
              if (!updatedData.subcategoryOptionsByCategoryJson) {
                updatedData.subcategoryOptionsByCategoryJson = {};
              }
              updatedData.subcategoryOptionsByCategoryJson[workflowData.CategoryCode] = subcategories;
              setInitialData(updatedData);
            }
          } catch (error) {
            console.warn('Could not load subcategories for existing category:', error);
          }
        }
      } else {
        // For new workflows, use server-side subcategory options if available
        if (subcategoryOptionsByCategoryJson && Object.keys(subcategoryOptionsByCategoryJson).length > 0) {
          setInitialData({ subcategoryOptionsByCategoryJson });
        }
      }
    } catch (err) {
      console.error('Error loading data:', err);
      setError(err.message || 'Failed to load data');
      showToast.error(err.message || 'Failed to load data', 3000);
      
      // Set treeDataError when the main API call fails
      // This ensures the retry button appears for tree data errors
      if (workflowId) {
        setTreeDataError(err.message || 'Failed to load data');
        setWorkflowTreeData([]);
      }
    } finally {
      setLoading(false);
    }
  }, [workflowId, subcategoryOptionsByCategoryJson]);

  // Unified function to fetch tree data with proper error handling
  const fetchTreeData = useCallback(async (setTreeLoading = null, explicitWorkflowId = null) => {
    // Use explicit ID if provided (for async state updates), otherwise use currentWorkflowId from state
    const workflowIdToUse = explicitWorkflowId || currentWorkflowId;
    
    if (!workflowIdToUse) {
      return [];
    }
    
    // Clear error, show loader
    setTreeDataError(null);
    if (setTreeLoading) setTreeLoading(true);
    
    try {
      const treeData = await workflowDefinitionApi.getWorkflowTree(workflowIdToUse);
      setWorkflowTreeData(treeData || []);
      // Success: clear loader, clear error
      if (setTreeLoading) setTreeLoading(false);
      setTreeDataError(null);
      return treeData || [];
    } catch (error) {
      console.error('Error fetching workflow tree data:', error);
      // Fail: set error, hide loader
      const errorMessage = error.message || 'Failed to load workflow tree data';
      setTreeDataError(errorMessage);
      if (setTreeLoading) setTreeLoading(false);
      // Show toast for retry attempts
      showToast.error(errorMessage, 5000);
      return [];
    }
  }, [currentWorkflowId, setWorkflowTreeData, setTreeDataError]);

  // Load data when component mounts
  useEffect(() => {
    loadData();
  }, [loadData]);

  // Retry function for tree data - uses the unified fetchTreeData function
  const retryTreeData = useCallback(async (setTreeLoading = null) => {
    try {
      const result = await fetchTreeData(setTreeLoading);
      if (result && result.length > 0) {
      //  showToast.success('Tree data loaded successfully', 3000);
      }
      return result;
    } catch (error) {
      console.error('Retry failed:', error);
      // Ensure loading state is cleared even if fetchTreeData fails
      if (setTreeLoading) setTreeLoading(false);
      throw error;
    }
  }, [fetchTreeData]);

  // Beforeunload warning for unsaved changes (matches legacy behavior)
  useEffect(() => {
    const handleBeforeUnload = (e) => {
      // Check for unsaved changes in workflow form
      if (formChanged) {
        e.preventDefault();
        e.returnValue = "Changes you made may not be saved.";
        return e.returnValue;
      }
      
      // Check for newly created tasks
      if (taskDetail && taskDetail.NewlyCreated) {
        e.preventDefault();
        e.returnValue = "The new task definition has not yet been saved. Do you want to continue without saving?";
        return e.returnValue;
      }
    };

    window.addEventListener('beforeunload', handleBeforeUnload);
    return () => window.removeEventListener('beforeunload', handleBeforeUnload);
  }, [formChanged, taskDetail]);

  return {
    // State
    drawerOpen,
    setDrawerOpen,
    saving,
    setSaving,
    validating,
    setValidating,
    loading,
    setLoading,
    error,
    setError,
    activeTab,
    setActiveTab,
    options,
    setOptions,
    initialData,
    setInitialData,
    formRef,
    workflowTreeData,
    setWorkflowTreeData,
    treeDataError,
    setTreeDataError,
    retryTreeData,
    currentTask,
    setCurrentTask,
    taskDetailLoading,
    setTaskDetailLoading,
    taskDetail,
    setTaskDetail,
    taskFetchError,
    setTaskFetchError,
    formChanged,
    setFormChanged,
    searchUDFModalOpen,
    setSearchUDFModalOpen,
    adhocSettingsModalOpen,
    setAdhocSettingsModalOpen,
    preconditionsModalOpen,
    setPreconditionsModalOpen,
    insertSnippetModalOpen,
    setInsertSnippetModalOpen,
    settingsModalOpen,
    setSettingsModalOpen,
    confirmationDialog,
    setConfirmationDialog,
    
    // Full page loader state
    fullPageLoader,
    setFullPageLoader,
    
    // Additional state for dynamic workflowId management
    currentWorkflowId,
    setWorkflowId: setCurrentWorkflowId,
    
    // Functions
    loadData,
    fetchTreeData,
    retryTreeData
  };
};
