import React, { useCallback, useState, useRef, useMemo, lazy, Suspense } from 'react';
import { 
  Box, 
  Grid, 
  Paper, 
  IconButton,
  Backdrop
} from '@mui/material';
import FAWTypography from '../../../FAWTypography';
import FAWTooltip from '../../../FAWTooltip';
import FAWButton from '../../../FAWButton';

import SearchIcon from "@diligentcorp/atlas-react-icons/dist/esm/lens/Search.js";
import SettingsIcon from "@diligentcorp/atlas-react-icons/dist/esm/lens/Settings.js";
import EditIcon from "@diligentcorp/atlas-react-icons/dist/esm/lens/Edit.js";
import ArrowLeftIcon from "@diligentcorp/atlas-react-icons/dist/esm/lens/ArrowLeft.js";

import ExpandIcon from "@diligentcorp/atlas-react-icons/dist/esm/lens/Expand.js";
import CollapseIcon from "@diligentcorp/atlas-react-icons/dist/esm/lens/Collapse.js";
import FAWDrawer from '../../../FAWDrawer';
import FAWSkeleton from '../../../FAWSkeleton';
import FAWLoader from '../../../FAWLoader';
import FAWErrorBoundary from '../../../errorHandling/FAWErrorBoundary';
import FAWConfirmDialogue from '../../../FAWConfirmDialogue';
import { ToastManager } from '../../../shared/ToastManager';
import WorkflowDefinitionForm from './WorkflowDefinitionForm';
import TaskManagementSection from './TaskManagementSection';
// PERFORMANCE: Lazy load heavy modals/drawers that are only opened on user action
const SearchUDFDrawer = lazy(() => import('../../../shared/SearchUDFDrawer'));
const AdhocSettingsModal = lazy(() => import('../../../shared/AdhocSettingsModal'));
const TaskSettingsModal = lazy(() => import('./TaskSettingsModal'));
import NoResultsFound from '../../../shared/NoResultsFound';
import AddTaskDropdown from './AddTaskDropdown';
import { useWorkflowDefinitionState } from '../hooks/useWorkflowDefinitionState';
import '../../css/workflow.css';
import { useWorkflowDefinitionHandlers } from '../hooks/useWorkflowDefinitionHandlers';
import { isNewlyCreated, getWarningMessage } from '../../../shared/utils/formChangeDetection';

const WorkflowDefinitionManager = ({ workflowId, taskId, subcategoryOptionsByCategoryJson, onSuccess, onCancel }) => {
  const state = useWorkflowDefinitionState({ workflowId, subcategoryOptionsByCategoryJson, onSuccess, onCancel });
  
  // Ref for WorkflowTaskDetail to access checkForChanges function
  const taskDetailRef = useRef(null);
  
  // State to track tree visibility for IF tasks
  // treeVisible = true means tree is hidden, task content is expanded (full width)
  // treeVisible = false means tree is visible, normal split view
  const [treeVisible, setTreeVisible] = useState(false);
  
  // Reset tree visibility when task changes (tree visible by default)
  React.useEffect(() => {
    setTreeVisible(false);
  }, [state.currentTask?.id]);
  
  const handleAddTask = (taskType) => {
    if (state.currentWorkflowId) {
      // Check if task is newly created via ref FIRST
      const isNew = taskDetailRef?.current?.isNewlyCreated;
      
      // Check for changes using the WorkflowTaskDetail component's checkForChanges function
      let hasChanges = false;
      if (taskDetailRef?.current?.checkForChanges) {
        hasChanges = taskDetailRef.current.checkForChanges();
      } else {
        // Fallback to parent state if ref is not available
        hasChanges = state.formChanged;
      }
      
      if (isNew || hasChanges) {
        // Get appropriate warning message using boolean flags
          const warningMessage = getWarningMessage(isNew, hasChanges);
        
        state.setConfirmationDialog({
          open: true,
          title: warningMessage?.title || 'Unsaved Changes',
          message: warningMessage?.message || 'You have unsaved changes. Are you sure you want to continue?',
          onConfirm: () => {
            state.setConfirmationDialog(prev => ({ ...prev, open: false }));
            createTask(taskType);
          },
          onCancel: () => {
            state.setConfirmationDialog(prev => ({ ...prev, open: false }));
          },
          confirmText: 'Continue',
          cancelText: 'Cancel',
          severity: warningMessage?.severity || 'warning'
        });
        return;
      }
      
      createTask(taskType);
    }
  };

  const createTask = (taskType) => {
    const event = new CustomEvent('addTaskRequested', {
      detail: {
        workflowId: state.currentWorkflowId,
        parentTaskId: 0,
        taskType: taskType
      }
    });
    window.dispatchEvent(event);
  };
  
  const handlers = useWorkflowDefinitionHandlers({
    workflowId: state.currentWorkflowId,
    taskId: taskId,
    onSuccess,
    onCancel,
    formRef: state.formRef,
    taskDetailRef: taskDetailRef,
    saving: state.saving,
    setSaving: state.setSaving,
    setValidating: state.setValidating,
    setDrawerOpen: state.setDrawerOpen,
    setError: state.setError,
    setCurrentTask: state.setCurrentTask,
    setTaskDetailLoading: state.setTaskDetailLoading,
    setTaskDetail: state.setTaskDetail,
    setTaskFetchError: state.setTaskFetchError,
    setFormChanged: state.setFormChanged,
    setSearchUDFModalOpen: state.setSearchUDFModalOpen,
    setAdhocSettingsModalOpen: state.setAdhocSettingsModalOpen,
    setPreconditionsModalOpen: state.setPreconditionsModalOpen,
    setInsertSnippetModalOpen: state.setInsertSnippetModalOpen,
    setConfirmationDialog: state.setConfirmationDialog,
    currentTask: state.currentTask,
    taskDetail: state.taskDetail,
    formChanged: state.formChanged,
    setWorkflowId: state.setWorkflowId,
    setInitialData: state.setInitialData,
    setWorkflowTreeData: state.setWorkflowTreeData,
    setLoading: state.setLoading,
    setFullPageLoader: state.setFullPageLoader,
    fetchTreeData: state.fetchTreeData,
    setTreeDataError: state.setTreeDataError
  });
  
  const handleCurrentTaskClear = React.useCallback(() => {
    state.setCurrentTask(null);
    state.setTaskDetail(null);
    state.setFormChanged(false);    
    if (taskId) {
      
      const currentUrl = new URL(window.location.href);
      currentUrl.searchParams.delete('taskId');
      if (!currentUrl.searchParams.has('id') && state.currentWorkflowId) {
        currentUrl.searchParams.set('id', state.currentWorkflowId);
      }
      window.history.replaceState({}, '', currentUrl.toString());
    }
  }, [state.setCurrentTask, state.setTaskDetail, state.setFormChanged, taskId, state.currentWorkflowId]);

  React.useEffect(() => {
    try {
      if (taskId && state.workflowTreeData && state.workflowTreeData.length > 0) {
        const findTaskInTree = (nodes, targetId) => {
          for (const node of nodes) {
            if (String(node.id) === String(targetId)) {
              return node;
            }
            if (node.children && node.children.length > 0) {
              const found = findTaskInTree(node.children, targetId);
              if (found) return found;
            }
          }
          return null;
        };

        const targetTask = findTaskInTree(state.workflowTreeData, taskId);
        
        if (targetTask) {
          handlers.handleNodeSelect(targetTask);
        }
      }
    } catch (error) {
      console.error('Error in taskId useEffect:', error);
    }
  }, [taskId, state.workflowTreeData]);

  React.useEffect(() => {
    const handleTaskIdUpdate = (event) => {
      try {
        const { taskId: newTaskId, workflowId: eventWorkflowId } = event.detail;
        
        if (eventWorkflowId === state.currentWorkflowId) {
          const findTaskInTree = (nodes, targetId) => {
            for (const node of nodes) {
              if (String(node.id) === String(targetId)) {
                return node;
              }
              if (node.children && node.children.length > 0) {
                const found = findTaskInTree(node.children, targetId);
                if (found) return found;
              }
            }
            return null;
          };

          const targetTask = findTaskInTree(state.workflowTreeData, newTaskId);
          if (targetTask) {
            handlers.handleNodeSelect(targetTask);
          }
        }
      } catch (error) {
        console.error('Error handling taskIdUpdated event:', error);
      }
    };

    window.addEventListener('taskIdUpdated', handleTaskIdUpdate);

    return () => {
      window.removeEventListener('taskIdUpdated', handleTaskIdUpdate);
    };
  }, [state.currentWorkflowId, state.workflowTreeData]);

  const isNewWorkflow = !state.currentWorkflowId || state.currentWorkflowId === 0;
  const showTreeView = !isNewWorkflow;

  const tabs = [
    { label: 'Workflow Details' },
    ...(state.currentWorkflowId ? [{ label: 'Task Management' }] : [])
  ];

  // Memoize drawer actions to prevent unnecessary re-renders and stale closures
  const drawerActions = useMemo(() => [
    {
      text: 'Cancel',
      variant: 'outlined',
      color: 'inherit',
      onClick: handlers.handleCloseDrawer,
      disabled: state.saving,
      handlerType: 'custom'
    },
    {
      text: state.validating ? 'Validating...' : state.saving ? 'Saving...' : 'Save',
      variant: 'contained',
      color: 'primary',
      onClick: handlers.handleSaveClick,
      disabled: state.saving || state.validating,
      handlerType: 'custom',
      componentType: 'workflow-definition'
    }
  ], [handlers.handleCloseDrawer, handlers.handleSaveClick, state.saving, state.validating]);


  React.useEffect(() => {
    const handleNavigateToTask = (event) => {
      const { taskId, workflowId: searchWorkflowId } = event.detail;
      if (searchWorkflowId === state.currentWorkflowId && state.workflowTreeData && state.workflowTreeData.length > 0) {
        // Find the task in the tree and select it
        const findTaskInTree = (nodes, targetId) => {
          for (const node of nodes) {
            if (String(node.id) === String(targetId)) {
              return node;
            }
            if (node.children && node.children.length > 0) {
              const found = findTaskInTree(node.children, targetId);
              if (found) return found;
            }
          }
          return null;
        };

        const targetTask = findTaskInTree(state.workflowTreeData, taskId);
        if (targetTask) {
          handlers.handleNodeSelect(targetTask);
        }
      }
    };

    window.addEventListener('navigateToTask', handleNavigateToTask);
    return () => {
      window.removeEventListener('navigateToTask', handleNavigateToTask);
    };
  }, [state.currentWorkflowId, state.workflowTreeData, handlers]);

  return (
    <FAWErrorBoundary
      title="Workflow Definition Error"
      message="An error occurred while loading the workflow definition. Please try again or contact support if the problem persists."
      showDetails={true}
      onError={(error, errorInfo) => {
        console.error('WorkflowDefinitionManager Error:', error, errorInfo);
      }}
      onReportError={(error) => {
        // Error reported by user
      }}
    >
      <Box sx={{ 
        width: '100% !important', 
        maxWidth: '100% !important', 
        overflow: 'hidden !important',
        boxSizing: 'border-box !important'
      }}>
        <ToastManager />

        {showTreeView && (
          <Box sx={{ 
            //backgroundColor: '#fbfbfb',
            minHeight: '100vh',
            width: '100% !important',
            maxWidth: '100% !important',
            overflow: 'hidden !important',
            boxSizing: 'border-box !important'
          }}>
            <Box sx={{ 
              display: 'flex', 
              justifyContent: 'space-between', 
              alignItems: 'center',
              //p: '16px 0',
              //backgroundColor: 'white',
              width: '100% !important',
              maxWidth: '100% !important',
              overflow: 'hidden !important',
              boxSizing: 'border-box !important',
              mb: 3
            }}>
              <Box sx={{ 
                display: 'flex', 
                alignItems: 'center', 
                gap: '12px',
                flex: 1
              }}>
                <FAWButton
                  variant="text"
                  size="medium"
                  iconOnly
                  onClick={() => {
                    if (onCancel) {
                      onCancel();
                    }
                  }}
                  sx={{ 
                    minWidth: 'auto',
                    width: '40px',
                    height: '40px',
                    borderRadius: '8px',
                    '&:hover': {
                      backgroundColor: '#f5f5f5'
                    }
                  }}
                >
                  <ArrowLeftIcon sx={{ fontSize: '20px' }} />
                </FAWButton>
                
                <FAWTypography sx={{
                  fontWeight: 600,
                  fontSize: '30px',
                  lineHeight: '38px',
                  color: '#282e37',
                  letterSpacing: '0.2px'
                }}>
                  {state.initialData?.Name || (workflowId ? 'Edit Workflow' : 'Create Workflow')}
                </FAWTypography>
              </Box>

              <Box sx={{ 
                display: 'flex', 
                alignItems: 'center', 
                gap: '16px'
              }}>
                <FAWButton
                  className="workflow-definition-manager-edit-workflow-btn"
                  variant="contained"
                  size="small"
                  startIcon={<EditIcon />}
                  onClick={() => state.setDrawerOpen(true)}
                  disabled={state.loading || (workflowId && !state.initialData)}
                >
                  Edit Attributes
                </FAWButton>
              </Box>
            </Box>
            
            <Grid container spacing={3} sx={{ 
              width: '100%',
              maxWidth: '100% !important',
              minHeight: 600,
              boxSizing: 'border-box',
              margin: 0
            }}>
            <Grid item xs={12} md={state.currentTask?.Type === 'IF' && treeVisible ? 0 : 4} className="workflow-definition-manager-tree-panel" sx={{ 
              minWidth: 0,
              maxWidth: '100% !important',
              overflow: 'hidden !important',
              display: state.currentTask?.Type === 'IF' && treeVisible ? 'none' : 'block',
              boxSizing: 'border-box'
            }}>
              <Paper className="workflow-definition-manager-tree-paper" sx={{ 
                height: '100%', 
                display: 'flex', 
                flexDirection: 'column',
                backgroundColor: 'white',
                borderRadius: '12px',
                border: '1px solid #dadada',
                boxShadow: 'none',
                overflow: 'hidden !important',
                maxWidth: '100% !important',
                width: '100% !important',
                minWidth: 0,
                boxSizing: 'border-box'
              }}>
                <Box className="workflow-definition-manager-tree-header" sx={{ 
                  p: '8px 16px',
                  borderBottom: '1px solid #dadada',
                  borderTopLeftRadius: '12px',
                  borderTopRightRadius: '12px',
                  display: 'flex',
                  justifyContent: 'space-between',
                  alignItems: 'center',
                  backgroundColor: 'white',
                  minHeight: '48px'
                }}>
                  <FAWTypography className="workflow-definition-manager-tree-title" sx={{
                    fontWeight: 600,
                    fontSize: '18px',
                    lineHeight: '28px',
                    color: '#282e37',
                    letterSpacing: '0.2px'
                  }}>
                    Workflow Definition
                  </FAWTypography>
                  <Box className="workflow-definition-manager-tree-actions" sx={{ display: 'flex', gap: '8px', background: 'none' }}>
                    <FAWTooltip title="Adhoc Settings">
                      <IconButton 
                        size="small"
                        onClick={() => {
                          if (state.currentWorkflowId && state.workflowTreeData && state.workflowTreeData.length > 0) {
                            handlers.handleAdhocSettingsOpen();
                          }
                        }}
                        disabled={!state.currentWorkflowId || !state.workflowTreeData || state.workflowTreeData.length === 0}
                        sx={{ color: '#666666' }}
                        aria-label="Adhoc Settings"
                      >
                        <SettingsIcon />
                      </IconButton>
                    </FAWTooltip>

                    <FAWTooltip title="Search UDF">
                      <IconButton 
                        size="small"
                        onClick={() => {
                          if (state.currentWorkflowId && state.workflowTreeData && state.workflowTreeData.length > 0) {
                            handlers.handleSearchUDFOpen();
                          }
                        }}
                        disabled={!state.currentWorkflowId || !state.workflowTreeData || state.workflowTreeData.length === 0}
                        sx={{ color: '#666666' }}
                      >
                        <SearchIcon />
                      </IconButton>
                    </FAWTooltip>

                    <AddTaskDropdown 
                      onAddTask={handleAddTask}
                      disabled={!state.currentWorkflowId || !state.workflowTreeData || state.workflowTreeData.length === 0}
                    />
                  </Box>
                </Box>

                <Box sx={{ 
                  flex: 1, 
                  overflow: 'auto', 
                  overflowX: 'hidden',
                  overflowY: 'auto',
                  p: '8px 16px 16px 8px',
                  backgroundColor: 'white',
                  borderBottomLeftRadius: '12px',
                  borderBottomRightRadius: '12px',
                  minWidth: 0,
                  width: '100% !important',
                  maxWidth: '100% !important',
                  boxSizing: 'border-box'
                }}>
                  <TaskManagementSection
                    workflowId={state.currentWorkflowId}
                    workflowTreeData={state.workflowTreeData}
                    currentTask={state.currentTask}
                    taskDetailLoading={state.taskDetailLoading}
                    taskDetail={state.taskDetail}
                    setTaskDetail={state.setTaskDetail}
                    taskFetchError={state.taskFetchError}
                    formChanged={state.formChanged}
                    setFormChanged={state.setFormChanged}
                    searchUDFModalOpen={state.searchUDFModalOpen}
                    preconditionsModalOpen={state.preconditionsModalOpen}
                    insertSnippetModalOpen={state.insertSnippetModalOpen}
                    onNodeSelect={handlers.handleNodeSelect}
                    onTreeAction={handlers.handleTreeAction}
                    onTreeError={handlers.handleTreeError}
                    onSearchUDFOpen={handlers.handleSearchUDFOpen}
                    onSearchUDFClose={handlers.handleSearchUDFClose}
                    onPreconditionsOpen={handlers.handlePreconditionsOpen}
                    onPreconditionsClose={handlers.handlePreconditionsClose}
                    onInsertSnippetOpen={handlers.handleInsertSnippetOpen}
                    onInsertSnippetClose={handlers.handleInsertSnippetClose}
                    onTreeDataRefresh={handlers.handleTreeDataRefresh}
                    setConfirmationDialog={state.setConfirmationDialog}
                    showTreeOnly={true}
                    fullPageLoader={state.fullPageLoader}
                    setFullPageLoader={state.setFullPageLoader}
                    error={state.error}
                    onCurrentTaskClear={handleCurrentTaskClear}
                    treeDataError={state.treeDataError}
                    retryTreeData={state.retryTreeData}
                  />
                </Box>
              </Paper>
            </Grid>

            <Grid item xs={12} md={state.currentTask?.Type === 'IF' && treeVisible ? 12 : 8} sx={{ 
              minWidth: 0,
              minHeight: 0,
              maxWidth: '100% !important',
              display: 'flex',
              flexDirection: 'column',
              boxSizing: 'border-box'
            }}>
              <Paper className="workflow-definition-manager-content-paper" sx={{ 
                height: '100%', 
                display: 'flex', 
                flexDirection: 'column',
                backgroundColor: 'white',
                borderRadius: '12px',
                border: '1px solid #dadada',
                boxShadow: 'none !important',
                overflow: 'hidden !important',
                maxWidth: '100% !important',
                width: '100% !important',
                minWidth: 0,
                boxSizing: 'border-box'
              }}>
                <Box className="workflow-definition-manager-content-header" sx={{ 
                  p: '16px',
                  display: 'flex',
                  justifyContent: 'space-between',
                  alignItems: 'center',
                  backgroundColor: 'white',
                  borderTopLeftRadius: '12px',
                  borderTopRightRadius: '12px'
                }}>
                  {state.currentTask ? (
                    <FAWTypography className="workflow-definition-manager-content-title" sx={{
                      overflow: 'hidden',
                      color: 'var(--Color-Type-Default, #282E37)',
                      textOverflow: 'ellipsis',
                      fontSize: '18px',
                      fontStyle: 'normal',
                      fontWeight: 600,
                      lineHeight: '28px',
                      letterSpacing: '0.2px'
                    }}>
                      {state.taskDetail?.Name || state.taskDetail?.name || state.currentTask.Name || state.currentTask.name || 'Untitled Task'}
                    </FAWTypography>
                  ) : (
                   null
                  )}
                  {state.currentTask && state.taskDetail && (
                    <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                      {/* Expand/Collapse icon for IF tasks */}
                      {state.currentTask?.Type === 'IF' && (
                        <IconButton 
                          className="workflow-definition-manager-tree-toggle-button"
                          size="small" 
                          onClick={() => setTreeVisible(!treeVisible)}
                          sx={{ color: '#666666' }}
                          title={treeVisible ? 'Show Tree (Collapse Task)' : 'Hide Tree (Expand Task)'}
                        >
                          {treeVisible ? <CollapseIcon /> : <ExpandIcon />}
                        </IconButton>
                      )}
                      {/* Settings icon */}
                      <IconButton 
                        className="workflow-definition-manager-task-settings-button"
                        size="small" 
                        onClick={() => state.setSettingsModalOpen(true)}
                        sx={{ color: '#666666' }}
                      >
                        <SettingsIcon />
                      </IconButton>
                    </Box>
                  )}
                </Box>

                <Box className="workflow-definition-manager-content-area" 
                  sx={{ 
                  flex: 1, 
                  overflowY: 'auto',
                  overflowX: 'hidden',
                  minHeight: 0,
                  //p: '16px',
                  backgroundColor: 'white',
                  borderBottomLeftRadius: '12px',
                  borderBottomRightRadius: '12px',
                  minWidth: 0,
                  maxWidth: '100% !important',
                  width: '100% !important',
                  boxSizing: 'border-box !important',
                  '& > *': {
                    maxWidth: '100% !important',
                    width: '100% !important',
                    boxSizing: 'border-box !important'
                  }
                }}>
                  {state.currentTask ? (
                    <Box sx={{
                      maxWidth: '100% !important',
                      width: '100% !important',
                      boxSizing: 'border-box !important'
                    }}>
                      <TaskManagementSection
                      workflowId={state.currentWorkflowId}
                      workflowTreeData={state.workflowTreeData}
                      currentTask={state.currentTask}
                      taskDetailLoading={state.taskDetailLoading}
                      taskDetail={state.taskDetail}
                      setTaskDetail={state.setTaskDetail}
                      taskFetchError={state.taskFetchError}
                      formChanged={state.formChanged}
                      setFormChanged={state.setFormChanged}
                      taskDetailRef={taskDetailRef}
                      searchUDFModalOpen={state.searchUDFModalOpen}
                      preconditionsModalOpen={state.preconditionsModalOpen}
                      insertSnippetModalOpen={state.insertSnippetModalOpen}
                      onNodeSelect={handlers.handleNodeSelect}
                      onTreeAction={handlers.handleTreeAction}
                      onTreeError={handlers.handleTreeError}
                      onSearchUDFOpen={handlers.handleSearchUDFOpen}
                      onSearchUDFClose={handlers.handleSearchUDFClose}
                      onPreconditionsOpen={handlers.handlePreconditionsOpen}
                      onPreconditionsClose={handlers.handlePreconditionsClose}
                      onInsertSnippetOpen={handlers.handleInsertSnippetOpen}
                      onInsertSnippetClose={handlers.handleInsertSnippetClose}
                      onTreeDataRefresh={handlers.handleTreeDataRefresh}
                      onTaskCancel={handlers.handleTaskCancel}
                      setConfirmationDialog={state.setConfirmationDialog}
                      showContentOnly={true}
                      fullPageLoader={state.fullPageLoader}
                      setFullPageLoader={state.setFullPageLoader}
                      error={state.error}
                      onCurrentTaskClear={handleCurrentTaskClear}
                      treeDataError={state.treeDataError}
                      retryTreeData={state.retryTreeData}
                    />
                    </Box>
                  ) : (
                    <NoResultsFound
                      title="No content"
                      subtitle="Click a task in the tree to view and manage its details"
                      className="workflow-definition-manager-no-task-selected"
                    />
                  )}
                </Box>
              </Paper>
            </Grid>
          </Grid>
          </Box>
        )}

        <FAWDrawer
          open={state.drawerOpen}
          onClose={handlers.handleCloseDrawer}
          title={state.currentWorkflowId ? 'Edit Workflow Definition' : 'Create Workflow Definition'}
          width={600}
          anchor="right"
          variant="temporary"
          showCloseButton={true}
          showHeader={true}
          customFooter={true}
          actions={drawerActions}
        >
          {state.loading ? (
            <Box sx={{ p: 3 }}>
              <FAWSkeleton variant="form" />
            </Box>
          ) : (
            <WorkflowDefinitionForm
              ref={state.formRef}
              workflowId={state.currentWorkflowId}
              onSave={handlers.handleSaveClick}
              onCancel={handlers.handleCancel}
              initialData={state.initialData}
              options={state.options}
              subcategoryOptionsByCategoryJson={subcategoryOptionsByCategoryJson}
            />
          )}
        </FAWDrawer>

        {/* PERFORMANCE: Lazy loaded modals with Suspense fallback */}
        <Suspense fallback={<FAWLoader label="Loading..." size={20} inline={false} />}>
          <SearchUDFDrawer
            open={state.searchUDFModalOpen}
            onClose={handlers.handleSearchUDFClose}
            entityId={state.currentWorkflowId}
            entityType="workflow"
          />
        </Suspense>

        <Suspense fallback={<FAWLoader label="Loading..." size={20} inline={false} />}>
          <AdhocSettingsModal
            open={state.adhocSettingsModalOpen}
            onClose={handlers.handleAdhocSettingsClose}
            entityId={state.currentWorkflowId}
            entityType="workflow"
            initialData={state.initialData}
            onSave={handlers.handleAdhocSettingsSave}
          />
        </Suspense>

        <Suspense fallback={<FAWLoader label="Loading..." size={20} inline={false} />}>
          <TaskSettingsModal
            open={state.settingsModalOpen}
            onClose={() => state.setSettingsModalOpen(false)}
            workflowId={state.currentWorkflowId}
            taskId={state.currentTask?.id}
            onSave={handlers.handleTaskSettingsSave}
            readOnly={false}
            isSectionTask={state.currentTask?.Type === 'SECTION'}
            isSnippet={false}
          />
        </Suspense>

        <FAWConfirmDialogue
          open={state.confirmationDialog.open}
          title={state.confirmationDialog.title}
          message={state.confirmationDialog.message}
          onConfirm={state.confirmationDialog.onConfirm}
          onClose={state.confirmationDialog.onCancel}
          confirmLabel={state.confirmationDialog.confirmText}
          cancelLabel={state.confirmationDialog.cancelText}
          variant={state.confirmationDialog.severity === 'error' ? 'delete' : 'info'}
        />

        <Backdrop
          open={state.fullPageLoader.open}
          sx={{
            zIndex: (theme) => theme.zIndex.drawer + 1,
            backgroundColor: 'rgba(0, 0, 0, 0.5)',
            backdropFilter: 'blur(2px)'
          }}
        >
          <FAWLoader 
            label={state.fullPageLoader.message}
            size={40}
            inline={false}
            sx={{
              backgroundColor: 'transparent',
              borderRadius: 0,
              padding: 0,
              boxShadow: 'none',
              minWidth: 'auto',
              maxWidth: 'none',
              '& .MuiTypography-root': {
                color: 'white',
                fontWeight: 500,
                textShadow: '0 1px 2px rgba(0, 0, 0, 0.5)'
              }
            }}
          />
        </Backdrop>
      </Box>
    </FAWErrorBoundary>
  );
};

export default WorkflowDefinitionManager;