import React, { useState, useEffect } from 'react';
import { Box, Typography } from '@mui/material';
import FAWModal from '../../../FAWModal';
import FAWButton from '../../../FAWButton';
import FAWSkeleton from '../../../FAWSkeleton';
import { workflowDefinitionApi } from '../services/workflowDefinitionApi';

const PreconditionsModal = ({ open, onClose, onSave, workflowId, taskId }) => {
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);
  const [preconditionForm, setPreconditionForm] = useState(null);
  const [error, setError] = useState(null);

  // Load precondition form when modal opens
  useEffect(() => {
    if (open && workflowId && taskId) {
      loadPreconditionForm();
    }
  }, [open, workflowId, taskId]);

  const loadPreconditionForm = async () => {
    setLoading(true);
    setError(null);

    try {
      const formData = await workflowDefinitionApi.getPreconditionForm(workflowId, taskId);
      setPreconditionForm(formData);
    } catch (err) {
      setError(err.message || 'Failed to load precondition form');
    } finally {
      setLoading(false);
    }
  };

  const handleSave = async () => {
    if (!preconditionForm) return;

    setSaving(true);
    setError(null);

    try {
      const result = await workflowDefinitionApi.savePreconditions(workflowId, taskId, preconditionForm);
      if (onSave) {
        onSave(result);
      }
      onClose();
    } catch (err) {
      setError(err.message || 'Failed to save preconditions');
    } finally {
      setSaving(false);
    }
  };

  const modalContent = (
    <Box sx={{ p: 2, height: '100%', display: 'flex', flexDirection: 'column' }}>
      {loading ? (
        <Box sx={{ flex: 1 }}>
          <FAWSkeleton variant="modal" />
        </Box>
      ) : error ? (
        <Box sx={{ p: 2, backgroundColor: '#ffebee', borderRadius: 1, mb: 2 }}>
          <Typography variant="body2" color="error">
            {error}
          </Typography>
        </Box>
      ) : (
        <>
          {/* Precondition Form Content */}
          <Box sx={{ flex: 1, overflowY: 'auto', mb: 2 }}>
            <Typography variant="body2" color="text.secondary">
              Precondition form functionality will be implemented with proper React components.
            </Typography>
          </Box>

          {/* Action Buttons */}
          <Box sx={{ display: 'flex', gap: 2, justifyContent: 'flex-end', borderTop: '1px solid #e0e0e0', pt: 2 }}>
            <FAWButton
              variant="outlined"
              onClick={onClose}
              disabled={saving}
            >
              Cancel
            </FAWButton>
            <FAWButton
              variant="contained"
              onClick={handleSave}
              disabled={saving}
            >
              {saving ? 'Saving...' : 'Save'}
            </FAWButton>
          </Box>
        </>
      )}
    </Box>
  );

  return (
    <FAWModal
      open={open}
      onClose={onClose}
      title="Define Preconditions"
      content={modalContent}
      maxWidth="lg"
      fullWidth={true}
    />
  );
};

export default PreconditionsModal;
