import React, { useState, useEffect, forwardRef, useImperativeHandle, useRef, useCallback } from 'react';
import { Box, Alert, Typography } from '@mui/material';
import FAWInput from '../../../FAWInput';
import FAWTextarea from '../../../FAWTextarea';
import FAWDropdown from '../../../FAWDropdown';
import FAWCheckbox from '../../../FAWCheckbox';
import FAWButton from '../../../FAWButton';
import FAWToast from '../../../FAWToast';
import FAWSkeleton from '../../../FAWSkeleton';
import FAWLoader from '../../../FAWLoader';
import FAWErrorBoundary from '../../../errorHandling/FAWErrorBoundary';
import { workflowDefinitionApi } from '../services/workflowDefinitionApi';
import { validateWorkflowDefinition, validateFormField } from '../../shared/utils/validation';
import { useDebouncedCallback } from '../../shared/hooks/useDebounce';

const WorkflowDefinitionForm = forwardRef(({ workflowId, onSave, onCancel, initialData, options: initialOptions, saving: propSaving, subcategoryOptionsByCategoryJson }, ref) => {
  // Determine if we're in edit mode (workflowId exists and > 0)
  const isEditMode = workflowId && workflowId > 0;
  const [formData, setFormData] = useState({
    Id: null, // Include Id field for updates
    Name: '',
    Description: '',
    WorkflowTypeCode: '',
    StateTransitionDomain: '',
    CategoryCode: '',
    SubcategoryCode: '',
    InitializerTypeCd: '',
    Active: false,
    UseStarterSnippet: false,
    LockId: 0,
    SubcategoryOptionsByCategoryJson: ''
  });

  const [options, setOptions] = useState({
    workflowTypes: [],
    stateTransitionDomains: [],
    categories: [],
    subcategories: [],
    initializerTypes: []
  });
  
  // Subcategory management state
  const [subcategoryOptionsByCategory, setSubcategoryOptionsByCategory] = useState({});
  const [subcategoryLoading, setSubcategoryLoading] = useState(false);

  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);
  const [validating, setValidating] = useState(false);
  const [error, setError] = useState(null);
  const [fieldErrors, setFieldErrors] = useState({});
  const [toast, setToast] = useState({ open: false, message: '', type: 'info', duration: 3000 });

  // Enhanced form validation using Yup schemas
  const validateForm = async () => {
    try {
      // First validate with Yup schema
      const result = await validateWorkflowDefinition(formData);
      setFieldErrors(result.fieldErrors || {});
      
      // Then validate name uniqueness if name is provided
      if (formData.Name && formData.Name.trim().length > 0) {
        try {
          const nameValidationResult = await workflowDefinitionApi.checkName(formData.Name, workflowId);
          if (!nameValidationResult.isValid) {
            result.fieldErrors = result.fieldErrors || {};
            result.fieldErrors.Name = nameValidationResult.message;
            result.isValid = false;
          }
        } catch (err) {
          console.error('Name validation error:', err);
          result.fieldErrors = result.fieldErrors || {};
          result.fieldErrors.Name = 'Error validating name uniqueness';
          result.isValid = false;
        }
      }
      
      return result;
    } catch (error) {
      console.error('Validation error:', error);
      const errorResult = {
        isValid: false,
        fieldErrors: { general: 'Validation error occurred' }
      };
      setFieldErrors(errorResult.fieldErrors);
      return errorResult;
    }
  };

  const isFormValid = async () => {
    try {
      setValidating(true);
      setError(null); // Clear any previous errors
      
      // Add timeout to prevent hanging
      const timeoutPromise = new Promise((_, reject) => 
        setTimeout(() => reject(new Error('Validation timeout')), 10000)
      );
      
      const validationResult = await Promise.race([
        validateForm(),
        timeoutPromise
      ]);
      
      return validationResult.isValid;
    } catch (error) {
      console.error('Form validation error:', error);
      if (error.message === 'Validation timeout') {
        setError('Validation timed out. Please try again.');
      } else {
        setError('Validation failed due to an unexpected error');
      }
      return false;
    } finally {
      setValidating(false);
    }
  };

  // Clear field error when field value changes
  const clearFieldError = (fieldName) => {
    if (fieldErrors[fieldName]) {
      const newErrors = { ...fieldErrors };
      delete newErrors[fieldName];
      setFieldErrors(newErrors);
    }
  };

  // Debounced field validation using Yup
  const validateFieldDebounced = useDebouncedCallback(async (fieldName, value) => {
    try {
      const result = await validateFormField('workflow', fieldName, value);
      if (!result.isValid) {
        setFieldErrors(prev => ({ ...prev, [fieldName]: result.error }));
      } else {
        clearFieldError(fieldName);
      }
    } catch (error) {
      console.error('Field validation error:', error);
    }
  }, 1000); // 1000ms delay

  // Function to focus on first error field
  const focusFirstError = useCallback(() => {
    const errorFields = Object.keys(fieldErrors);
    if (errorFields.length > 0) {
      const firstErrorField = errorFields[0];
      const element = document.getElementById(`workflow-${firstErrorField.toLowerCase()}`);
      if (element) {
        element.scrollIntoView({ behavior: 'smooth', block: 'center' });
        element.focus();
      }
    }
  }, [fieldErrors]);

  // Expose methods to parent component
  useImperativeHandle(ref, () => ({
    getFormData: () => formData,
    isFormValid: isFormValid, // Return function reference, not call it
    focusFirstError
  }));

  // Load workflow data and options
  useEffect(() => {
    loadData();
  }, [workflowId]);

  // Cleanup effect to reset validation state
  useEffect(() => {
    return () => {
      // Reset validation state when component unmounts
      setValidating(false);
      setError(null);
      setFieldErrors({});
    };
  }, []);

  // Update options when initialOptions prop changes
  useEffect(() => {
    if (initialOptions) {
      setOptions(initialOptions);
      
      // Auto-select first State Transition Domain option in create mode (skip placeholder)
      if (!isEditMode && initialOptions.stateTransitionDomains && initialOptions.stateTransitionDomains.length > 0) {
        // Find first option with a non-empty value (skip placeholder like '-- Select --')
        const firstValidOption = initialOptions.stateTransitionDomains.find(opt => opt && opt.value && opt.value.trim() !== '');
        if (firstValidOption && firstValidOption.value) {
          setFormData(prev => {
            // Only auto-select if no value is currently set
            if (!prev.StateTransitionDomain) {
              return { ...prev, StateTransitionDomain: firstValidOption.value };
            }
            return prev;
          });
        }
      }
    }
  }, [initialOptions, isEditMode]);

  // Load subcategory options when prop changes
  useEffect(() => {
    if (subcategoryOptionsByCategoryJson && Object.keys(subcategoryOptionsByCategoryJson).length > 0) {
      loadSubcategoryOptions(subcategoryOptionsByCategoryJson);
    }
  }, [subcategoryOptionsByCategoryJson]);

  // Watch for category changes and load subcategories automatically
  useEffect(() => {
    if (formData.CategoryCode) {
      updateSubcategories(formData.CategoryCode);
    } else {
      setOptions(prev => ({ ...prev, subcategories: [] }));
    }
  }, [formData.CategoryCode]);

  // Load subcategories on mount if category is already selected
  useEffect(() => {
    if (formData.CategoryCode && !subcategoryLoading) {
      updateSubcategories(formData.CategoryCode);
    }
  }, []); // Empty dependency array = run only on mount

  const loadData = () => {
    setLoading(true);
    setError(null);
    
    try {
      // Set options from props
      if (initialOptions) {
        setOptions(initialOptions);
      }

      // Set initial form data if provided with safety checks
      if (initialData && typeof initialData === 'object') {
        setFormData(prev => ({
          ...prev,
          Id: initialData.Id || null, // Include the Id field for updates
          Name: initialData.Name || '',
          Description: initialData.Description || '',
          WorkflowTypeCode: initialData.WorkflowTypeCode || '',
          StateTransitionDomain: initialData.StateTransitionDomain || '',
          CategoryCode: initialData.CategoryCode || '',
          SubcategoryCode: initialData.SubcategoryCode || '',
          Active: initialData.Active !== undefined ? initialData.Active : false,
          UseStarterSnippet: initialData.UseStarterSnippet || false,
          LockId: initialData.LockId || 0
        }));
        
        // Load subcategory options if available
        if (initialData.SubcategoryOptionsByCategoryJson) {
          loadSubcategoryOptions(initialData.SubcategoryOptionsByCategoryJson);
        }
        
        // Load subcategories for the selected category
        if (initialData.CategoryCode) {
          updateSubcategories(initialData.CategoryCode);
        }
      } else {
        // For new workflows, use server-side subcategory options if available
        if (subcategoryOptionsByCategoryJson && Object.keys(subcategoryOptionsByCategoryJson).length > 0) {
          loadSubcategoryOptions(subcategoryOptionsByCategoryJson);
        }
      }
    } catch (err) {
      console.error('Error loading data:', err);
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleInputChange = (field, value) => {
    try {
      // Ensure value is not undefined or null
      const safeValue = value !== undefined && value !== null ? value : '';
      
      setFormData(prev => ({ ...prev, [field]: safeValue }));
      
      // Clear subcategory selection when category changes
      if (field === 'CategoryCode') {
        setFormData(prev => ({ ...prev, SubcategoryCode: '' }));
      }
    } catch (error) {
      console.error('Error in handleInputChange:', error);
      setError('Error updating form field');
    }
  };


  const updateSubcategories = async (categoryCode) => {
    if (!categoryCode) {
      setOptions(prev => ({ ...prev, subcategories: [] }));
      return;
    }

    setSubcategoryLoading(true);
    try {
      // Make API call to get subcategories for the selected category
      const subcategories = await workflowDefinitionApi.getSubcategories(categoryCode);
      setOptions(prev => ({ ...prev, subcategories }));
    } catch (error) {
      console.error('Error loading subcategories:', error);
      setOptions(prev => ({ ...prev, subcategories: [] }));
    } finally {
      setSubcategoryLoading(false);
    }
  };

  // Load subcategory options from server-side data
  const loadSubcategoryOptions = (subcategoryOptionsJson) => {
    if (subcategoryOptionsJson) {
      try {
        // Check if it's already an object or needs to be parsed
        const parsedOptions = typeof subcategoryOptionsJson === 'string' 
          ? JSON.parse(subcategoryOptionsJson) 
          : subcategoryOptionsJson;
        setSubcategoryOptionsByCategory(parsedOptions);
      } catch (err) {
        console.error('Error parsing subcategory options:', err);
        console.error('subcategoryOptionsJson:', subcategoryOptionsJson);
      }
    }
  };

  const handleToastClose = () => {
    setToast({ open: false, message: '', type: 'info', duration: 3000 });
  };

  if (loading) {
    return (
      <Box sx={{ p: 3 }}>
        <FAWSkeleton variant="form" />
      </Box>
    );
  }

  return (
    <FAWErrorBoundary
      title="Form Error"
      message="An error occurred while rendering the workflow definition form. Please try again."
      showDetails={false}
      onError={(error, errorInfo) => {
        console.error('WorkflowDefinitionForm Error:', error, errorInfo);
      }}
    >
      <Box sx={{ p: 3, position: 'relative' }} role="main" aria-label="Workflow Definition Form">
        {/*Toast for notifications */}
        <FAWToast 
          open={toast.open} 
          message={toast.message} 
          type={toast.type} 
          duration={toast.duration}
          onClose={handleToastClose} 
        />

      {error && (
        <Alert severity="error" sx={{ mb: 3 }} role="alert" aria-live="polite">
          {error}
        </Alert>
      )}

      <form onSubmit={(e) => e.preventDefault()} aria-label="Workflow Definition Form" noValidate>
        <Box sx={{ display: 'flex', flexDirection: 'column', gap: 3 }}>
          {/* Name Field */}
        <FAWInput
          id="workflow-name"
          label="Name"
          placeholder="Enter workflow name"
          value={formData.Name}
          onChange={(e) => handleInputChange('Name', e.target.value)}
          error={!!fieldErrors.Name}
          helperText={fieldErrors.Name}
          variant="outlined"
          fullWidth
          required
          aria-describedby="workflow-name-helper"
          aria-invalid={!!fieldErrors.Name}
          labelSx={{
            fontSize: '14px',
            fontWeight: 500
          }}
          sx={{
            '& .MuiOutlinedInput-root': {
              backgroundColor: '#ffffff'
            }
          }}
        />

        {/* Description Field */}
        <FAWTextarea
          id="workflow-description"
          label="Description"
          placeholder="Enter workflow description"
          value={formData.Description}
          onChange={(e) => handleInputChange('Description', e.target.value)}
          error={!!fieldErrors.Description}
          helperText={fieldErrors.Description}
          rows={3}
          variant="outlined"
          fullWidth
          sx={{
            '& .MuiOutlinedInput-root': {
              backgroundColor: '#ffffff'
            }
          }}
        />

        {/* Active Checkbox */}
        <FAWCheckbox
          id="workflow-active"
          label="Active"
          checked={formData.Active}
          onChange={(e) => handleInputChange('Active', e.target.checked)}
          size="medium"
        />

        {/* Use Starter Snippet Checkbox - Only show if ShowStarterSnippetOption is true */}
        {initialData?.ShowStarterSnippetOption && (
          <FAWCheckbox
            id="workflow-use-starter-snippet"
            label="Use Starter Snippet"
            checked={formData.UseStarterSnippet}
            onChange={(e) => handleInputChange('UseStarterSnippet', e.target.checked)}
            size="medium"
            title="Use the starter snippet as the starting point"
          />
        )}

        {/* Workflow Definition Type */}
        <FAWDropdown
          id="workflow-type"
          label="Workflow Definition Type"
          value={formData.WorkflowTypeCode || ''}
          onChange={(option) => handleInputChange('WorkflowTypeCode', option?.value || '')}
          options={options.workflowTypes}
          loading={loading && options.workflowTypes.length === 0}
          error={!!fieldErrors.WorkflowTypeCode}
          helperText={fieldErrors.WorkflowTypeCode}
          fullWidth
          required
          // Legacy allows editing in edit mode - removed disabled={isEditMode}
        />

        {/* State Transition Domain */}
        <FAWDropdown
          id="state-transition-domain"
          label="State Transition Domain"
          value={formData.StateTransitionDomain || ''}
          onChange={(option) => handleInputChange('StateTransitionDomain', option?.value || '')}
          options={options.stateTransitionDomains || []}
          loading={loading && (!options.stateTransitionDomains || options.stateTransitionDomains.length === 0)}
          error={!!fieldErrors.StateTransitionDomain}
          helperText={fieldErrors.StateTransitionDomain}
          fullWidth
          required
        />

        {/* Category */}
        <FAWDropdown
          id="workflow-category"
          label="Category"
          value={formData.CategoryCode || ''}
          onChange={(option) => handleInputChange('CategoryCode', option?.value || '')}
          options={[]}
          loading={false}
          error={!!fieldErrors.CategoryCode}
          helperText={fieldErrors.CategoryCode}
          fullWidth
        />

        {/* Subcategory */}
        <FAWDropdown
          id="workflow-subcategory"
          label="Subcategory"
          value={formData.SubcategoryCode || ''}
          onChange={(option) => handleInputChange('SubcategoryCode', option?.value || '')}
          options={options.subcategories}
          disabled={!formData.CategoryCode || subcategoryLoading}
          loading={subcategoryLoading}
          error={!!fieldErrors.SubcategoryCode}
          helperText={fieldErrors.SubcategoryCode}
          fullWidth
          placeholder={!formData.CategoryCode ? 'Select category before selecting subcategory' : 
                     subcategoryLoading ? 'Loading subcategories...' :
                     options.subcategories.length === 0 ? 'No subcategories available under selected category' : 
                     '-- SELECT --'}
        />

        {/* Custom Task Initializer */}
        <FAWDropdown
          id="custom-task-initializer"
          label="Custom Task Initializer"
          value={formData.InitializerTypeCd || ''}
          onChange={(option) => handleInputChange('InitializerTypeCd', option?.value || '')}
          options={options.initializerTypes}
          loading={loading && options.initializerTypes.length === 0}
          placeholder={options.initializerTypes.length === 0 ? 'No options available' : '-- SELECT --'}
          fullWidth
          // Legacy allows editing in edit mode - removed disabled={isEditMode}
        />


        </Box>
      </form>
      
      {/* FAWToast for notifications*/}
      <FAWToast 
        open={toast.open} 
        message={toast.message} 
        type={toast.type} 
        duration={toast.duration}
        onClose={handleToastClose} 
      />

      {/* Saving Loader Overlay */}
      {propSaving && (
        <Box sx={{
          position: 'absolute',
          top: 0,
          left: 0,
          right: 0,
          bottom: 0,
          backgroundColor: 'rgba(255, 255, 255, 0.8)',
          backdropFilter: 'blur(2px)',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          zIndex: 1000
        }}>
          <FAWLoader 
            size={40} 
            label={workflowId ? 'Updating workflow definition...' : 'Creating workflow definition...'} 
            inline={false}
          />
        </Box>
      )}
      </Box>
    </FAWErrorBoundary>
  );
});

export default WorkflowDefinitionForm;
