import React, { useState } from 'react';
import { Box, Typography, Alert, IconButton, Button } from '@mui/material';
import FAWTooltip from '../../../FAWTooltip';
import { Refresh as RefreshIcon } from '@mui/icons-material';
import FAWAlert from '../../../FAWAlert';
import FAWButton from '../../../FAWButton';
import FAWSkeleton from '../../../FAWSkeleton';
import FAWErrorBoundary from '../../../errorHandling/FAWErrorBoundary';
import WorkflowTree from '../../../../Workflow/WorkflowTree';
import SearchUDFModal from '../../../shared/SearchUDFModal';
import PreconditionsModal from './PreconditionsModal';
import InsertSnippetModal from '../../../shared/InsertSnippetModal';
import WorkflowTaskDetail from './WorkflowTaskDetail';
import { workflowDefinitionApi } from '../services/workflowDefinitionApi';
import { showToast } from '../../../shared/ToastManager';

const TaskManagementSection = ({
  workflowId,
  workflowTreeData,
  currentTask,
  taskDetailLoading,
  taskDetail,
  setTaskDetail,
  taskFetchError,
  formChanged,
  setFormChanged,
  taskDetailRef,
  searchUDFModalOpen,
  preconditionsModalOpen,
  insertSnippetModalOpen,
  onNodeSelect,
  onTreeAction,
  onTreeError,
  onSearchUDFOpen,
  onSearchUDFClose,
  onPreconditionsOpen,
  onPreconditionsClose,
  onInsertSnippetOpen,
  onInsertSnippetClose,
  onTreeDataRefresh,
  onTaskCancel,
  setConfirmationDialog,
  showTreeOnly = false,
  showContentOnly = false,
  fullPageLoader,
  setFullPageLoader,
  error,
  onCurrentTaskClear,
  treeDataError,
  retryTreeData
}) => {
  const [treeLoading, setTreeLoading] = useState(false);
  const [treeError, setTreeError] = useState(null);

  const handleTreeError = (error, isTreeDataError = false) => {
    let errorMessage = 'An error occurred while processing the request.';
    
    if (typeof error === 'string') {
      errorMessage = error;
    } else if (error?.message) {
      errorMessage = error.message;
    } else if (error?.response?.data?.message) {
      errorMessage = error.response.data.message;
    } else if (error?.response?.statusText) {
      errorMessage = error.response.statusText;
    }
    
    setTreeError(errorMessage);
    showToast.error(errorMessage, 30000);
    
    // Only update the global treeDataError state for specific tree data loading errors
    // This ensures that only GetWorkflowDefinitionApi failures show the retry button
    if (isTreeDataError && onTreeError) {
      onTreeError(errorMessage);
    }
  };


  React.useEffect(() => {
    const handleAddTaskRequest = (event) => {
      const { workflowId, parentTaskId, taskType } = event.detail;
      
      if (workflowId && taskType) {
        const addTaskFunction = async () => {
          setFullPageLoader({
            open: true,
            message: `Creating ${taskType} task...`
          });
          setTreeError(null);
          try {
            const result = await workflowDefinitionApi.addTask(workflowId, parentTaskId, taskType);
            
            // Only refresh tree if the operation was successful
            if (result && result.success !== false) {
              showToast.success(result.message || 'Task added successfully', 30000);
              
              if (onTreeDataRefresh) {
                await onTreeDataRefresh();
              }
            } else {
              throw new Error(result?.message || 'Failed to add task');
            }
            
            
            if (result.taskId && onNodeSelect) {
              // Wait a bit for the tree to re-render with the new data
              await new Promise(resolve => setTimeout(resolve, 100));
              
              const newTask = {
                id: result.taskId,
                Name: `New ${taskType}`,
                Type: taskType,
              };
              
              try {
                onNodeSelect(newTask);
              } catch (error) {
                console.error('ADD TASK: Error in onNodeSelect:', error);
              }
              
              const currentUrl = new URL(window.location.href);
              currentUrl.searchParams.set('taskId', result.taskId);
              window.history.replaceState({}, '', currentUrl.toString());
              
              const event = new CustomEvent('taskIdUpdated', {
                detail: { taskId: result.taskId, workflowId: workflowId }
              });
              window.dispatchEvent(event);
            }
          } catch (error) {
            handleTreeError(error);
          } finally {
            setFullPageLoader(prev => ({ ...prev, open: false }));
          }
        };
        
        addTaskFunction();
      }
    };

    window.addEventListener('addTaskRequested', handleAddTaskRequest);

    return () => {
      window.removeEventListener('addTaskRequested', handleAddTaskRequest);
    };
  }, [onTreeDataRefresh, onNodeSelect]);

  const handleSuccess = (message) => {
    showToast.success(message, 30000);
  };

  const handleInsertSnippetSave = async (data) => {
    try {
      const result = await workflowDefinitionApi.insertSnippet(data.workflowId, data.taskId, data.snippetId);
      // Only refresh tree if the operation was successful
      if (result && result.success) {
        showToast.success(result.message || 'Snippet inserted successfully', 30000);
        
        if (onTreeDataRefresh) {
          await onTreeDataRefresh();
        }
      } else {
        throw new Error(result?.message || 'Failed to insert snippet');
      }
    } catch (error) {
      showToast.error(error.message || 'Failed to insert snippet', 30000);
      // Don't refresh tree on error
    }
  };

  const hasValidWorkflowId = workflowId && workflowId !== 0;

  if (!hasValidWorkflowId) {
    return null;
  }

  const renderWorkflowTree = () => (
    <FAWErrorBoundary
      title="Workflow Tree Error"
      message="An error occurred while rendering the workflow tree. The tree functionality may be limited."
      showDetails={false}
      onError={(error, errorInfo) => {
        onTreeError(error);
      }}
    >
      <WorkflowTree
        currentTask={currentTask}
        readOnly={false}
        treeDataJson={workflowTreeData}
        handleNodeSelect={onNodeSelect}
        handleAction={onTreeAction}
        loading={!workflowTreeData || treeLoading}
        workItem={{ 
          id: workflowId || 0, 
          allowAdhocFlowEdit: true,
          isEditable: true 
        }}
        height="100%"
        showSearchBar={false}
        isDefinitionMode={true}
        updateTreeAsync={async (nodeId, parentId, index, treeData, handleError) => {
          setTreeLoading(true);
          setTreeError(null);
          try {
            const result = await workflowDefinitionApi.updateWorkflowTreeStructure(workflowId, nodeId, parentId, index);
            
            if (result.success) {
              handleSuccess(result.message || 'Tree structure updated successfully');
              if (onTreeDataRefresh) {
                await onTreeDataRefresh();
              }
            } else {
              throw new Error(result.message || 'Failed to update tree structure');
            }
          } catch (error) {
            handleTreeError(error);
          } finally {
            setFullPageLoader(prev => ({ ...prev, open: false }));
          }
        }}
        removeTaskAsync={async (workflowId, taskId, handleError) => {
          if (setConfirmationDialog) {
            setConfirmationDialog({
              open: true,
              title: 'Confirm Removal',
              message: 'Are you sure you want to remove this task from the workflow?',
              onConfirm: async () => {
                setConfirmationDialog({ open: false });
                setFullPageLoader({
                  open: true,
                  message: 'Removing task...'
                });
                setTreeError(null);
                
                try {
                  const result = await workflowDefinitionApi.removeTask(workflowId, taskId);
                  
                  // Only refresh tree if the operation was successful
                  if (result && result.success !== false) {
                    showToast.success(result.message || 'Task removed successfully', 30000);
                    
                    // Clear current task if it was the removed one
                    if (currentTask && currentTask.id === taskId && onCurrentTaskClear) {
                      onCurrentTaskClear();
                    }
                    
                    if (onTreeDataRefresh) {
                      await onTreeDataRefresh();
                    }
                  } else {
                    throw new Error(result?.message || 'Failed to remove task');
                  }
                } catch (error) {
                  handleTreeError(error);
                } finally {
                  setFullPageLoader(prev => ({ ...prev, open: false }));
                }
              },
              onCancel: () => {
                setConfirmationDialog({ open: false });
              },
              confirmText: 'Yes, Remove',
              cancelText: 'Cancel',
              severity: 'error'
            });
          } else {
            setFullPageLoader({
              open: true,
              message: 'Removing task...'
            });
            setTreeError(null);
            try {
              const result = await workflowDefinitionApi.removeTask(workflowId, taskId);
              // Only refresh tree if the operation was successful
              if (result && result.success !== false) {
                handleSuccess(result.message || 'Task removed successfully');
                
                // Clear current task if it was the removed one
                if (currentTask && currentTask.id === taskId && onCurrentTaskClear) {
                  onCurrentTaskClear();
                }
                
                if (onTreeDataRefresh) {
                  await onTreeDataRefresh();
                }
              } else {
                throw new Error(result?.message || 'Failed to remove task');
              }
            } catch (error) {
              handleTreeError(error);
            } finally {
              setFullPageLoader(prev => ({ ...prev, open: false }));
            }
          }
        }}
        restoreTaskAsync={async (workflowId, taskId, handleError) => {
          setFullPageLoader({
            open: true,
            message: 'Restoring task...'
          });
          setTreeError(null);
          try {
            const result = await workflowDefinitionApi.restoreTask(workflowId, taskId);
            // Only refresh tree if the operation was successful
            if (result && result.success !== false) {
              handleSuccess(result.message || 'Task restored successfully');
              if (onTreeDataRefresh) {
                await onTreeDataRefresh();
              }
            } else {
              throw new Error(result?.message || 'Failed to restore task');
            }
          } catch (error) {
            handleTreeError(error);
            // Don't refresh tree on error
          } finally {
            setFullPageLoader(prev => ({ ...prev, open: false }));
          }
        }}
        addTaskAsync={async (workflowId, parentTaskId, taskType, handleError) => {
          setFullPageLoader({
            open: true,
            message: `Creating ${taskType} task...`
          });
          setTreeError(null);
          try {
            const result = await workflowDefinitionApi.addTask(workflowId, parentTaskId, taskType);
            // Only refresh tree if the operation was successful
            if (result && result.success !== false) {
              handleSuccess(result.message || 'Task added successfully');
              
              if (onTreeDataRefresh) {
                await onTreeDataRefresh();
              }
            } else {
              throw new Error(result?.message || 'Failed to add task');
            }
            
            
           if (result.taskId && onNodeSelect) {
             // Wait a bit longer for the tree to re-render with the new data
             await new Promise(resolve => setTimeout(resolve, 300));
             
             const newTask = {
               id: result.taskId,
               Name: `New ${taskType}`,
               Type: taskType,
             };
             
             try {
               onNodeSelect(newTask);
             } catch (error) {
               console.error('ADD TASK ASYNC: Error in onNodeSelect:', error);
               // Show a warning but don't fail the entire operation
               showToast.warning('Task created but auto-selection failed. Please manually select the new task.', 5000);
             }
             
             // Update URL and dispatch event
             const currentUrl = new URL(window.location.href);
             currentUrl.searchParams.set('taskId', result.taskId);
             window.history.replaceState({}, '', currentUrl.toString());
             
             const event = new CustomEvent('taskIdUpdated', {
               detail: { taskId: result.taskId, workflowId: workflowId }
             });
             window.dispatchEvent(event);
           }
          } catch (error) {
            handleTreeError(error);
          } finally {
            setFullPageLoader(prev => ({ ...prev, open: false }));
          }
        }}
        saveTaskPredecessorAsync={(() => {
          const saveFn = async (workflowId, taskId, finalPredecessorIds, handleError) => {
            setFullPageLoader({
              open: true,
              message: 'Saving predecessors...'
            });
            setTreeError(null);
            try {
              const result = await workflowDefinitionApi.saveTaskPredecessors(workflowId, taskId, finalPredecessorIds);
              // Only refresh tree if the operation was successful
              if (result && result.success) {
                handleSuccess(result.message || 'Predecessors saved successfully');
                if (onTreeDataRefresh) {
                  await onTreeDataRefresh();
                }
              } else {
                throw new Error(result?.message || 'Failed to save predecessors');
              }
            } catch (error) {
              handleTreeError(error);
              // Don't refresh tree on error
            } finally {
              setFullPageLoader(prev => ({ ...prev, open: false }));
            }
          };
          saveFn.getTaskPredecessors = (workflowId, taskId) => workflowDefinitionApi.getTaskPredecessors(workflowId, taskId);
          return saveFn;
        })()}
        loadSnippetsAsync={async (workflowId) => {
          try {
            const snippets = await workflowDefinitionApi.getSnippets(workflowId);
            return snippets;
          } catch (error) {
            handleTreeError(error);
            return [];
          }
        }}
        moveTaskAsync={async (workflowId, taskId, isUp, handleError) => {
          const moveMessage = isUp ? 'Moving task up...' : 'Moving task down...';
          setFullPageLoader({
            open: true,
            message: moveMessage
          });
          setTreeError(null);
          try {
            const result = await workflowDefinitionApi.moveTask(workflowId, taskId, isUp);
            // Only refresh tree if the operation was successful
            if (result && result.success !== false) {
              const successMessage = isUp ? 'Task moved up successfully' : 'Task moved down successfully';
              handleSuccess(result.message || successMessage);
              if (onTreeDataRefresh) {
                await onTreeDataRefresh();
              }
            } else {
              throw new Error(result?.message || 'Failed to move task');
            }
          } catch (error) {
            handleTreeError(error);
            // Don't refresh tree on error
          } finally {
            setFullPageLoader(prev => ({ ...prev, open: false }));
          }
        }}
        moveTaskToSectionAsync={async (workflowId, sourceId, targetId, handleError) => {
          setFullPageLoader({
            open: true,
            message: 'Moving task to section...'
          });
          setTreeError(null);
          try {
            const result = await workflowDefinitionApi.moveTaskToSection(workflowId, sourceId, targetId);
            // Only refresh tree if the operation was successful
            if (result && result.success !== false) {
              handleSuccess(result.message || 'Task moved to section successfully');
              if (onTreeDataRefresh) {
                await onTreeDataRefresh();
              }
            } else {
              throw new Error(result?.message || 'Failed to move task to section');
            }
          } catch (error) {
            handleTreeError(error);
            // Don't refresh tree on error
          } finally {
            setFullPageLoader(prev => ({ ...prev, open: false }));
          }
        }}
        saveInsertSnippetAsync={async (snippetData, handleError) => {
          setFullPageLoader({
            open: true,
            message: 'Inserting snippet...'
          });
          setTreeError(null);
          
          try {
            const result = await workflowDefinitionApi.insertSnippet(
              snippetData.containerId, 
              snippetData.taskId, 
              snippetData.snippetId
            );
            
            if (result.success) {
              showToast.success(result.message || 'Snippet inserted successfully');
              
              if (onTreeDataRefresh) {
                await onTreeDataRefresh();
              }
            } else {
              throw new Error(result.message || 'Failed to insert snippet');
            }
          } catch (error) {
            handleTreeError(error);
          } finally {
            setFullPageLoader(prev => ({ ...prev, open: false }));
          }
        }}
        handleError={onTreeError}
      />
    </FAWErrorBoundary>
  );

  if (showTreeOnly) {
    return (
      <Box>
        {treeLoading && (
          <Box sx={{ p: 2 }}>
            <FAWSkeleton variant="workflowTree" />
          </Box>
        )}

        {/* Show retry button when tree data failed to load */}
        {!treeLoading && treeDataError && (
          <Box sx={{ 
            p: 3, 
            display: 'flex', 
            flexDirection: 'column', 
            alignItems: 'center', 
            justifyContent: 'center',
            height: '200px',
            textAlign: 'center'
          }}>
            <Typography variant="body1" color="text.secondary" sx={{ mb: 2 }}>
              Failed to load workflow tree data
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 3 }}>
              {treeDataError}
            </Typography>
            <FAWTooltip title="Retry loading tree data">
              <IconButton
                onClick={() => retryTreeData(setTreeLoading)}
                sx={{
                  backgroundColor: '#f5f5f5',
                  '&:hover': {
                    backgroundColor: '#e0e0e0'
                  }
                }}
              >
                <RefreshIcon />
              </IconButton>
            </FAWTooltip>
          </Box>
        )}

        {/* {(error || treeError) && (
          <Alert severity="error" sx={{ mb: 2 }} onClose={() => {
            setTreeError(null);
          }}>
            {error || treeError}
          </Alert>
        )} */}

        {!treeLoading && !treeDataError && renderWorkflowTree()}
      </Box>
    );
  }

  if (showContentOnly) {
    return (
      <Box>
        {currentTask && (
          <Box>
            <WorkflowTaskDetail
              ref={taskDetailRef}
              taskDetail={taskDetail}
              loading={taskDetailLoading}
              workflowId={workflowId}
              taskId={currentTask?.id}
              onFormChange={(changed) => {
                if (setFormChanged) {
                  setFormChanged(changed);
                }
              }}
              onSave={async (formData) => {
                try {
                  const result = await workflowDefinitionApi.saveTaskDetail(formData);
                  
                  if (result.success) {
                    handleSuccess(result.message || 'Task details saved successfully');
                    
                    // Refresh tree data to reflect name changes in the left panel.
                    // Do NOT call onNodeSelect here: it would trigger a second GetTaskDetail and race
                    // with WorkflowTaskDetail's single post-save refresh (redundant API call + risk of stale LockId).
                    if (onTreeDataRefresh) {
                      setTreeLoading(true);
                      try {
                        await onTreeDataRefresh();
                      } catch (refreshError) {
                        console.warn('Failed to refresh tree data after save:', refreshError);
                      } finally {
                        setTreeLoading(false);
                      }
                    }
                    
                    return result; // Return result so handleSave can check success
                  } else {
                    // Handle save failure
                    throw new Error(result.message || 'Failed to save task details');
                  }
                } catch (error) {
                  console.error('Error saving task details:', error);
                  throw error;
                }
              }}
              onTaskDetailUpdate={(updatedTaskDetail) => {
                if (setTaskDetail) {
                  setTaskDetail(updatedTaskDetail);
                }
              }}
              onCancel={() => {
                if (onTaskCancel) {
                  onTaskCancel(currentTask);
                }
              }}
              readOnly={false}
            />
          </Box>
        )}
      </Box>
    );
  }

  return (
    <Box sx={{ 
      display: 'flex', 
      height: '100%', 
      gap: 2,
      width: '100%',
      maxWidth: '100%',
      boxSizing: 'border-box',
      overflow: 'hidden'
    }}>
      <Box sx={{ 
        flex: '0 0 calc(40% - 8px)',
        minWidth: 0,
        maxWidth: 'calc(40% - 8px)',
        display: 'flex',
        flexDirection: 'column',
        borderRight: '1px solid #dadada',
        pr: 2,
        boxSizing: 'border-box',
        overflow: 'hidden'
      }}>
        {treeLoading && (
          <Box sx={{ p: 2 }}>
            <FAWSkeleton variant="workflowTree" />
          </Box>
        )}

        {(error || treeError) && (
          <Alert severity="error" sx={{ mb: 2 }} onClose={() => {
            setTreeError(null);
          }}>
            {error || treeError}
          </Alert>
        )}

        {!treeLoading && !treeDataError && renderWorkflowTree()}
      </Box>

      <Box sx={{ 
        flex: '0 0 calc(60% - 8px)',
        minWidth: 0,
        maxWidth: 'calc(60% - 8px)',
        display: 'flex',
        flexDirection: 'column',
        boxSizing: 'border-box',
        overflow: 'hidden'
      }}>
        {!currentTask && (
          <Box sx={{ 
            display: 'flex', 
            alignItems: 'center', 
            justifyContent: 'center', 
            height: '100%',
            color: '#666',
            fontSize: '16px',
            textAlign: 'center'
          }}>
            <Box>
              <Typography variant="h6" sx={{ mb: 1, color: '#999' }}>
                No Task Selected
              </Typography>
              <Typography variant="body2" sx={{ color: '#999' }}>
                Click a task in the tree to view and manage its details
              </Typography>
            </Box>
          </Box>
        )}

        {currentTask && taskFetchError && (
          <Box sx={{ 
            display: 'flex', 
            alignItems: 'center', 
            justifyContent: 'center', 
            height: '100%',
            color: '#666',
            fontSize: '16px',
            textAlign: 'center'
          }}>
            <Box>
              <Typography variant="h6" sx={{ mb: 1, color: '#d32f2f' }}>
                Unable to Fetch Task Details
              </Typography>
              <Typography variant="body2" sx={{ color: '#666', mb: 2 }}>
                {taskFetchError}
              </Typography>
              <Button
                variant="contained"
                startIcon={<RefreshIcon />}
                onClick={() => {
                  if (currentTask) {
                    onNodeSelect(currentTask);
                  }
                }}
                sx={{
                  backgroundColor: '#1976d2',
                  '&:hover': {
                    backgroundColor: '#1565c0'
                  }
                }}
              >
                Retry
              </Button>
            </Box>
          </Box>
        )}

        {currentTask && (
          <>
            <WorkflowTaskDetail
            ref={taskDetailRef}
            taskDetail={taskDetail}
            loading={taskDetailLoading}
            workflowId={workflowId}
            taskId={currentTask?.id}
            onFormChange={(changed) => {
              if (setFormChanged) {
                setFormChanged(changed);
              }
            }}
            onSave={async (formData) => {
              setFullPageLoader({
                open: true,
                message: 'Saving task details...'
              });
              try {
                const result = await workflowDefinitionApi.saveTaskDetail(formData);
                
                if (result.success) {
                  handleSuccess(result.message || 'Task details saved successfully');
                  
                  // Refresh tree data to reflect name changes in the left panel.
                  // Do NOT call onNodeSelect here: it would trigger a second GetTaskDetail and race
                  // with WorkflowTaskDetail's single post-save refresh (redundant API call + risk of stale LockId).
                  if (onTreeDataRefresh) {
                    setTreeLoading(true);
                    try {
                      await onTreeDataRefresh();
                    } catch (refreshError) {
                      console.warn('Failed to refresh tree data after save:', refreshError);
                    } finally {
                      setTreeLoading(false);
                    }
                  }
                  
                  return result; // Return result so handleSave can check success
                } else {
                  // Handle save failure
                  throw new Error(result.message || 'Failed to save task details');
                }
              } catch (error) {
                console.error('Error saving task details:', error);
                throw error;
              } finally {
                setFullPageLoader(prev => ({ ...prev, open: false }));
              }
            }}
            onTaskDetailUpdate={(updatedTaskDetail) => {
              if (setTaskDetail) {
                setTaskDetail(updatedTaskDetail);
              }
            }}
            onCancel={() => {
              if (onTaskCancel) {
                onTaskCancel(currentTask);
              }
            }}
            readOnly={false}
          />
          </>
        )}
      </Box>

      <Box sx={{ display: 'flex', gap: 2, mb: 2, flexWrap: 'wrap', p: 2 }}>
        <FAWButton
          variant="outlined"
          color="primary"
          onClick={onSearchUDFOpen}
          disabled={!hasValidWorkflowId}
          sx={{ minWidth: 120 }}
        >
          Find Additional Fields
        </FAWButton>
        
        <FAWButton
          variant="outlined"
          color="secondary"
          onClick={onPreconditionsOpen}
          disabled={!hasValidWorkflowId}
          sx={{ minWidth: 120 }}
        >
          Preconditions
        </FAWButton>
        
        <FAWButton
          variant="outlined"
          color="secondary"
          onClick={onInsertSnippetOpen}
          disabled={!hasValidWorkflowId}
          sx={{ minWidth: 120 }}
        >
          Insert Snippet
        </FAWButton>
      </Box>

      <SearchUDFModal
        open={searchUDFModalOpen && hasValidWorkflowId}
        onClose={onSearchUDFClose}
        entityId={workflowId}
        entityType="workflow"
      />

      <PreconditionsModal
        open={preconditionsModalOpen && hasValidWorkflowId}
        onClose={onPreconditionsClose}
        entityId={workflowId}
      />

      <InsertSnippetModal
        open={insertSnippetModalOpen && hasValidWorkflowId}
        onClose={onInsertSnippetClose}
        entityId={workflowId}
        entityType="workflow"
        taskId={currentTask?.id}
        getSnippetsApi={workflowDefinitionApi.getSnippets}
        onSave={handleInsertSnippetSave}
      />

    </Box>
  );
};

export default TaskManagementSection;