import React, { useState, useEffect, useMemo, useCallback, useImperativeHandle, useRef } from 'react';
import {
  Box,
  Grid, 
  Alert,
  Chip
} from '@mui/material';
import { isEqual, cloneDeep, omit } from 'lodash';
import { hasFormChangesByOmit, isNewlyCreated, getWarningMessage } from '../../../shared/utils/formChangeDetection';
import FAWButton from '../../../FAWButton';
import '../../css/workflow.css';
import FAWTypography from '../../../FAWTypography';
import { showToast } from '../../../shared/ToastManager';
import FAWSkeleton from '../../../FAWSkeleton';
import FAWLoader from '../../../FAWLoader';
import FAWErrorBoundary from '../../../errorHandling/FAWErrorBoundary';
import { validateWorkflowTaskDefinition } from '../utils/workflowTaskValidation';

// Import extracted components
import BasicTaskFields from '../../shared/components/BasicTaskFields';
import { 
  ActionTask,
  NotificationTask,
  CloseTask,
  SectionTask,
  StepTask,
  EditTask,
  ApproveTask,
  ReviewTask,
  RouteToTask,
  GoToTask,
  IfTask
} from '../../shared/components/taskTypes';

// Import shared utilities
import { 
  initializeFormData,
  validateForm,
  hasRequiredUDFs,
  areRequiredUDFsFilled,
  getTaskTypeFlags
} from '../../shared/utils';
import axios from '../../../../../Helpers/FetchCsrfToken';

/**
 * Workflow Task Detail Component
 * Renders the full task detail form for workflow definitions
 * Matches legacy WorkflowTaskDefView.cshtml functionality
 */
const WorkflowTaskDetail = React.forwardRef(({ 
  taskDetail, 
  loading, 
  onSave, 
  onCancel, 
  readOnly = false,
  workflowId,
  taskId,
  onFormChange,
  onTaskDetailUpdate
}, ref) => {
  const [formData, setFormData] = useState({});
  const [originalFormData, setOriginalFormData] = useState(null);
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState(null);
  const [fieldErrors, setFieldErrors] = useState({});
  const ifTaskRef = useRef(null);

  // On-demand change detection - only compute when needed
  const [formChanged, setFormChanged] = useState(false);
  
  // Function to check for changes only when called
  const checkForChanges = useCallback(() => {
    if (!formData || !originalFormData) {
      setFormChanged(false);
      return false;
    }
    
    const hasChanges = hasFormChangesByOmit(formData, originalFormData);
    setFormChanged(hasChanges);
    
    // Notify parent component
    if (onFormChange) {
      onFormChange(hasChanges);
    }
    
    return hasChanges;
  }, [formData, originalFormData, onFormChange]);

  // Track the last processed task ID to prevent unnecessary resets
  const [lastProcessedTaskId, setLastProcessedTaskId] = useState(null);

  // Update form data when taskDetail changes
  useEffect(() => {
    if (taskDetail && taskDetail.Id !== lastProcessedTaskId) {
      const initializedData = initializeFormData(taskDetail);
      
      // Always update form data when taskDetail changes (new task selected)
      // This ensures the form reflects the newly selected task
      setFormData(initializedData);
      setOriginalFormData(cloneDeep(initializedData)); // Store original data for comparison
      
      // Reset form changed state immediately for new task
      setFormChanged(false);
      
      // Notify parent component that form is reset
      if (onFormChange) {
        onFormChange(false);
      }
      
      setError(null);
      setFieldErrors({});
      
      // Update the last processed task ID
      setLastProcessedTaskId(taskDetail.Id);
    }
  }, [taskDetail?.Id, onFormChange, lastProcessedTaskId, formChanged]);



  // No automatic change detection - only when explicitly called

  // Expose methods to parent component via ref
  useImperativeHandle(ref, () => ({
    checkForChanges,
    formChanged,
    formData,
    originalFormData,
    isNewlyCreated: isNewlyCreated(formData)
  }), [checkForChanges, formChanged, formData, originalFormData]);

  const validateFormData = async (isCompletingTask = false) => {
    try {
      // Only validate UDFs when completing the task (matches legacy behavior)
      const result = await validateForm(formData, () => areRequiredUDFsFilled(formData, isCompletingTask));
      
      if (!result.isValid) {
        // Check if result has fieldErrors and extract first error
        let firstError = 'Validation failed';
        if (result.fieldErrors) {
          const errorKeys = Object.keys(result.fieldErrors);
          if (errorKeys.length > 0) {
            firstError = result.fieldErrors[errorKeys[0]];
          }
        } else if (result.errors && result.errors.length > 0) {
          firstError = result.errors[0];
        }
        
        setError(firstError);
        return false;
      }
      setError(null);
      return true;
    } catch (error) {
      console.error('WorkflowTaskDetail: Error in validateFormData:', error);
      setError('Validation error occurred');
      return false;
    }
  };

  // Handle form field changes
  const handleFieldChange = (field, value) => {
    setFormData(prev => {
      const newData = { ...prev, [field]: value };
      return newData;
    });
    
    // No automatic change detection - only when explicitly needed
    // Note: Errors are only cleared during final save operation
  };

  // Handle inline editing


  // Custom save function for conditional snippet tasks
  const saveConditionalSnippetTask = async () => {
    try {
      // Get CSRF token
      const csrfResponse = await fetch('/Tour/GetAntiForgeryToken');
      const csrfData = await csrfResponse.json();
      const csrfToken = csrfData.token;
      const cookieToken = csrfData.cookieToken;
      document.cookie = `CookieToken=${cookieToken}; path=/`;

      // Build filter groups from rule editor functions
      const filterGroups = [];
      if (window.conditionalSnippetSaveFunctions) {
        Object.keys(window.conditionalSnippetSaveFunctions).forEach(editorId => {
          const saveFunction = window.conditionalSnippetSaveFunctions[editorId];
          if (saveFunction) {
            const filterInfo = saveFunction();
            if (!filterInfo.errorMessage) {
              filterGroups.push({
                filter: filterInfo.filters[0],
                snippetId: filterInfo.snippetId,
                formId: filterInfo.formId
              });
            }
          }
        });
      }

      const taskDefinition = {
        filterGroups,
        evaluateAllConditions: formData.EvaluateAllConditions || 'true',
        name: formData.Name || '',
        description: formData.Description || '',
        status: formData.Status || '',
        workQueueId: formData.WorkQueueId || '',
        workflowTaskDefinitionId: taskId,
        newlyCreated: formData.NewlyCreated || 'False',
        isSnippetTask: formData.IsSnippetTask || 'False',
        containerId: workflowId,
        order: formData.Order || 0,
        parentWorkflowTaskDefinitionId: formData.ParentWorkflowTaskDefinitionId || '',
        lockId: formData.LockId || 0
      };

      const response = await axios.post('/WorkflowDef/SaveConditionalSnippetTaskDef', taskDefinition, {
        headers: {
          'Accept': 'application/json',
          'Content-Type': 'application/json',
          '__RequestVerificationToken': csrfToken
        }
      });

      const result = response.data;

      if (!result.success) {
        throw new Error(result.message || 'Failed to save conditional snippet task');
      }

      // Clear save functions
      if (window.conditionalSnippetSaveFunctions) {
        window.conditionalSnippetSaveFunctions = {};
      }
      
      // Trigger refresh or navigation
      if (!workflowId) {
        console.error('SAVE CONDITIONAL SNIPPET: workflowId is null or undefined!');
        throw new Error('WorkflowId is required but was not provided');
      }
      
      if (formData.IsSnippetTask === 'True') {
        // Navigate to snippet task edit
        window.location.href = `/WorkflowTaskDefSnippet/EditWorkflowTaskDef?workflowId=${workflowId}&id=${taskId}`;
      } else {
        // Navigate to regular task edit
        window.location.href = `/WorkflowDef/EditWorkflowTaskDef?workflowDefId=${workflowId}&id=${taskId}`;
      }
    } catch (error) {
      console.error('Error saving conditional snippet task:', error);
      throw error;
    }
  };

  // Handle save
  const handleSave = async () => {
    // Special handling for IF (Conditional Snippet) tasks
    // They need to use SaveConditionalSnippetTaskDef endpoint with filterGroups
    if (formData.Type === 'IF' && ifTaskRef.current) {
      setSaving(true);
      setError(null);
      
      try {
        const result = await ifTaskRef.current.save();
        
        if (result.success) {
          // If save was successful, fetch latest task data and update originalFormData
          if (workflowId && taskId && onTaskDetailUpdate) {
            try {
              const { workflowDefinitionApi } = await import('../services/workflowDefinitionApi');
              const updatedTaskDetail = await workflowDefinitionApi.getTaskDetail(workflowId, taskId);
              if (updatedTaskDetail?.success && updatedTaskDetail?.data) {
                onTaskDetailUpdate(updatedTaskDetail.data);
                const refreshedFormData = initializeFormData(updatedTaskDetail.data);
                setOriginalFormData(cloneDeep(refreshedFormData));
                setFormData(cloneDeep(refreshedFormData));
              }
            } catch (refreshError) {
              console.warn('Failed to refresh task detail after save:', refreshError);
              setOriginalFormData(cloneDeep(formData));
            }
          } else {
            setOriginalFormData(cloneDeep(formData));
          }
          
          setFormChanged(false);
          if (onFormChange) {
            onFormChange(false);
          }
        } else {
          setError(result.message || 'Failed to save conditional snippet task');
        }
      } catch (err) {
        setError(err.message || 'Failed to save task details');
      } finally {
        setSaving(false);
      }
      return;
    }
    
    // Note: Regular saves don't validate UDFs (matches legacy behavior)
    // UDFs are only validated when completing tasks (isCompletingTask = true)
    const isValid = await validateFormData(false); // false = not completing task
    if (!isValid) {
      return;
    }
    setSaving(true);
    setError(null);
    
    try {
      // Use standard save logic for all task types
      if (!onSave) return;
      const result = await onSave(formData);
      
      // If save was successful, fetch latest task data and update originalFormData
      if (result?.success && workflowId && taskId && onTaskDetailUpdate) {
        try {
          const { workflowDefinitionApi } = await import('../services/workflowDefinitionApi');
          const updatedTaskDetail = await workflowDefinitionApi.getTaskDetail(workflowId, taskId);
          if (updatedTaskDetail?.success && updatedTaskDetail?.data) {
            // Update parent component with refreshed data
            onTaskDetailUpdate(updatedTaskDetail.data);
            
            // Process the refreshed data through initializeFormData to get normalized form data
            // This ensures originalFormData matches what the server actually saved
            const refreshedFormData = initializeFormData(updatedTaskDetail.data);
            setOriginalFormData(cloneDeep(refreshedFormData));
            
            // Also update current formData to match server response (in case server modified anything)
            setFormData(cloneDeep(refreshedFormData));
          }
        } catch (refreshError) {
          console.warn('Failed to refresh task detail after save:', refreshError);
          // Fallback: use current formData if refresh fails
          setOriginalFormData(cloneDeep(formData));
        }
      } else if (result?.success) {
        // If refresh is not available (no workflowId/taskId), use current formData
        // This prevents false positives when checkForChanges() is called later
        setOriginalFormData(cloneDeep(formData));
      }
      
      setFormChanged(false);
      
      // Notify parent component that form is saved
      if (onFormChange) {
        onFormChange(false);
      }
    } catch (err) {
      console.error('WorkflowTaskDetail: Save failed:', err);
      setError(err.message || 'Failed to save task details');
    } finally {
      setSaving(false);
    }
  };

  // Form validation methods for external access
  const getFormData = () => {
    return formData;
  };

  const isFormValid = async () => {
    try {
      // Validate the form data using the comprehensive validation utility
      const validation = validateWorkflowTaskDefinition(formData);
      
      if (!validation.isValid) {
        // Set field-specific errors for display
        setFieldErrors(validation.errors);
        
        // Set general error message
        setError(Object.values(validation.errors).join('; '));
        
        return false;
      }
      
      // Clear any existing errors
      setError(null);
      setFieldErrors({});
      return true;
    } catch (err) {
      console.error('Error during form validation:', err);
      setError('Validation error occurred');
      return false;
    }
  };


  // Task type detection using utility functions
  const taskTypeFlags = getTaskTypeFlags(formData.Type);
  const { 
    isActionTask, 
    isNotificationTask, 
    isCloseTask, 
    isSectionTask, 
    isReviewTask, 
    isStepTask, 
    isRouteToTask,
    isEditTask,
    isApproveTask,
    isGoToTask,
    isIfTask
  } = taskTypeFlags;

  // Handle cancel - delegate to parent without showing local confirmation
  const handleCancel = () => {
    // Always call parent's onCancel handler
    // The parent will handle confirmation dialogs and API calls
    if (onCancel) {
      onCancel();
    }
  };

  if (loading || saving) {
    return (
      <Box className="workflow-task-detail-loading" sx={{ p: 1 }}>
        <FAWSkeleton className="workflow-task-detail-skeleton-header" variant="text" width="60%" height={32} sx={{ mb: 3 }} />
        <FAWSkeleton className="workflow-task-detail-skeleton-description" variant="rectangular" width="100%" height={56} sx={{ mb: 2 }} />
        <FAWSkeleton className="workflow-task-detail-skeleton-status" variant="rectangular" width="100%" height={56} sx={{ mb: 2 }} />
        <FAWSkeleton className="workflow-task-detail-skeleton-route" variant="rectangular" width="100%" height={80} sx={{ mb: 2 }} />
        <FAWSkeleton className="workflow-task-detail-skeleton-label" variant="text" width="40%" height={24} sx={{ mb: 2 }} />
        <FAWSkeleton className="workflow-task-detail-skeleton-fields" variant="rectangular" width="100%" height={120} sx={{ mb: 2 }} />
        <FAWSkeleton className="workflow-task-detail-skeleton-actions" variant="rectangular" width="100%" height={40} sx={{ mb: 2 }} />
        <Box className="workflow-task-detail-skeleton-buttons" sx={{ display: 'flex', gap: 2, mt: 3 }}>
          <FAWSkeleton className="workflow-task-detail-skeleton-save-btn" variant="rectangular" width={100} height={36} />
          <FAWSkeleton className="workflow-task-detail-skeleton-cancel-btn" variant="rectangular" width={80} height={36} />
        </Box>
      </Box>
    );
  }

  if (!taskDetail) {
    return (
      <Box className="workflow-task-detail-empty" sx={{ p: 3, textAlign: 'center' }}>
        <FAWTypography className="workflow-task-detail-empty-message" variant="body1" color="text.secondary">
          No task selected. Click a task in the tree to view its details.
        </FAWTypography>
      </Box>
    );
  }

  return (
    <FAWErrorBoundary
      title="Task Detail Error"
      message="An error occurred while rendering the task detail form."
      showDetails={false}
    >
      <Box className="workflow-task-detail-container" sx={{ 
        backgroundColor: 'white',
        borderRadius: '12px',
        boxShadow: 'none',
        display: 'flex',
        flexDirection: 'column',
        height: '100%',
        position: 'relative'
      }}>
        <Box className="workflow-task-detail-content" sx={{ 
          pt: '8px',
          px: '16px',
          pb: '8px',
          display: 'flex', 
          flexDirection: 'column', 
          gap: '16px',
          flex: 1
        }}>

          {/* Main Content Area */}
          <Box className="workflow-task-detail-main-content" sx={{ display: 'flex', flexDirection: 'column', gap: 2 }}>
          {/* Error Display */}
          {error && (
            <Alert className="workflow-task-detail-error-alert" severity="error" sx={{ mb: 2 }}>
              {error}
            </Alert>
          )}

          {/* {formChanged && (
            <Alert className="workflow-task-detail-warning-alert" severity="warning" sx={{ mb: 2 }}>
              You have unsaved changes.
            </Alert>
          )} */}

          {/* Basic Task Fields (Name, Description, Status, Route To, Field Management) */}
          <BasicTaskFields
            formData={formData}
            onFieldChange={handleFieldChange}
            readOnly={readOnly}
            fieldErrors={fieldErrors}
            isCloseTask={isCloseTask}
          />

          {/* Task Type Specific Components */}
          {isActionTask && (
            <Box className="workflow-task-detail-action-task">
              <ActionTask 
                formData={formData}
                onFieldChange={handleFieldChange}
                hasRequiredUDFs={() => areRequiredUDFsFilled(formData)}
                readOnly={readOnly}
                fieldErrors={fieldErrors}
                isCloseTask={isCloseTask}
              />
            </Box>
          )}
          {isNotificationTask && (
            <Box className="workflow-task-detail-notification-task">
              <NotificationTask 
                formData={formData}
                onFieldChange={handleFieldChange}
                hasRequiredUDFs={() => areRequiredUDFsFilled(formData)}
                readOnly={readOnly}
                fieldErrors={fieldErrors}
                isCloseTask={isCloseTask}
              />
            </Box>
          )}
          {isSectionTask && (
            <Box className="workflow-task-detail-section-task">
              <SectionTask 
                formData={formData}
                onFieldChange={handleFieldChange}
                hasRequiredUDFs={() => areRequiredUDFsFilled(formData)}
                readOnly={readOnly}
                fieldErrors={fieldErrors}
                isCloseTask={isCloseTask}
              />
            </Box>
          )}
          {isStepTask && (
            <Box className="workflow-task-detail-step-task">
              <StepTask 
                formData={formData}
                onFieldChange={handleFieldChange}
                hasRequiredUDFs={() => areRequiredUDFsFilled(formData)}
                readOnly={readOnly}
                fieldErrors={fieldErrors}
                isCloseTask={isCloseTask}
              />
            </Box>
          )}
          {isEditTask && (
            <Box className="workflow-task-detail-edit-task">
              <EditTask 
                formData={formData}
                onFieldChange={handleFieldChange}
                hasRequiredUDFs={() => areRequiredUDFsFilled(formData)}
                readOnly={readOnly}
                fieldErrors={fieldErrors}
                isCloseTask={isCloseTask}
              />
            </Box>
          )}
          {isApproveTask && (
            <Box className="workflow-task-detail-approve-task">
              <ApproveTask 
                formData={formData}
                onFieldChange={handleFieldChange}
                hasRequiredUDFs={() => areRequiredUDFsFilled(formData)}
                readOnly={readOnly}
                fieldErrors={fieldErrors}
                isCloseTask={isCloseTask}
              />
            </Box>
          )}
          {isReviewTask && (
            <Box className="workflow-task-detail-review-task">
              <ReviewTask 
                formData={formData}
                onFieldChange={handleFieldChange}
                hasRequiredUDFs={() => areRequiredUDFsFilled(formData)}
                readOnly={readOnly}
                fieldErrors={fieldErrors}
                isCloseTask={isCloseTask}
              />
            </Box>
          )}
          {isRouteToTask && (
            <Box className="workflow-task-detail-route-to-task">
              <RouteToTask 
                formData={formData}
                onFieldChange={handleFieldChange}
                hasRequiredUDFs={() => areRequiredUDFsFilled(formData)}
                readOnly={readOnly}
                fieldErrors={fieldErrors}
                isCloseTask={isCloseTask}
              />
            </Box>
          )}
          {isGoToTask && (
            <Box className="workflow-task-detail-go-to-task">
              <GoToTask 
                formData={formData}
                onFieldChange={handleFieldChange}
                hasRequiredUDFs={() => areRequiredUDFsFilled(formData)}
                readOnly={readOnly}
                fieldErrors={fieldErrors}
                isCloseTask={isCloseTask}
              />
            </Box>
          )}
          {isIfTask && (
            <Box className="workflow-task-detail-if-task">
              <IfTask 
                ref={ifTaskRef}
                formData={formData}
                onFieldChange={handleFieldChange}
                hasRequiredUDFs={() => areRequiredUDFsFilled(formData)}
                readOnly={readOnly}
                workflowDefId={workflowId}
                taskId={taskId}
                isSnippet={false}
                fieldErrors={fieldErrors}
                isCloseTask={isCloseTask}
              />
            </Box>
          )}
          {isCloseTask && (
            <Box className="workflow-task-detail-close-task">
              <CloseTask 
                key={`closetask-${formData?.Id}-${formData?.LockId}`}
                formData={formData}
                onFieldChange={handleFieldChange}
                hasRequiredUDFs={() => areRequiredUDFsFilled(formData)}
                readOnly={readOnly}
                fieldErrors={fieldErrors}
                isCloseTask={isCloseTask}
              />
            </Box>
          )}

        </Box>

          {/* Divider */}
          <Box sx={{ height: '1px', backgroundColor: '#dadada', width: '100%' }} />

          {/* Footer with Action Buttons */}
          <Box className="workflow-task-detail-footer" sx={{ 
            display: 'flex',
            gap: 2,
            justifyContent: 'space-between',
            alignItems: 'center',
            minHeight: '40px',
            //paddingTop: 2
          }}>
            <FAWButton
              className="workflow-task-detail-cancel-btn"
              variant="outlined"
              onClick={handleCancel}
              disabled={readOnly}
              size="small"
            >
              Cancel
            </FAWButton>
            
            <FAWButton
              className="workflow-task-detail-save-btn"
              variant="contained"
              onClick={handleSave}
              disabled={readOnly}
              size="small"
            >
              Save
            </FAWButton>
          </Box>
        </Box>
      </Box>
    </FAWErrorBoundary>
  );
});

// Expose methods via ref
WorkflowTaskDetail.displayName = 'WorkflowTaskDetail';

export default WorkflowTaskDetail;
